import { GoogleGenAI, Chat, GenerateContentResponse, Content } from "@google/genai";
import { DailyVerse } from "../types";

const SYSTEM_INSTRUCTION = `You are Lumen, a warm, wise, and empathetic Bible study assistant. 
Your goal is to help users understand the Bible, find comfort in scripture, and grow in their faith.

Key Responsibilities:
1. **Verse Lookup**: If a user inputs a specific Bible reference (e.g., "John 3:16", "Psalm 23", "1 Cor 13"), provide the full text of that passage immediately. Use the ESV or NIV translation. Format it clearly.
2. **Guidance**: When discussing topics, cite the book, chapter, and verse.
3. **Support**: If a user expresses distress, anxiety, or sadness, offer comforting verses and a gentle, prayerful tone.
4. **Prayer Requests**: When a user shares a prayer request, you must personalize your response deeply. 
   - **MANDATORY**: You must explicitly reference the specific people (by name if given), specific situations, medical conditions, or struggles mentioned in the user's request.
   - Example: If the user says "My mom has surgery", say "Lord, we lift up [User]'s mom to You as she undergoes surgery. Guide the surgeons' hands..." 
   - **PROHIBITED**: Do NOT use generic phrases like "be with this situation" or "unspoken request" if specific details are available.
   - Mirror the user's language and emotional tone to ensure they feel truly heard.

Guidelines:
- Always be respectful, non-denominational, and encouraging.
- Keep responses concise and easy to read on a mobile device.
- Do not be judgmental. Meet the user where they are in their spiritual journey.`;

let chatSession: Chat | null = null;

// Initialize the Gemini client
// STRICT COMPLIANCE: Use process.env.API_KEY directly.
const getAiClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const getChatSession = (history?: Content[]): Chat => {
  if (!chatSession) {
    const ai = getAiClient();
    chatSession = ai.chats.create({
      model: 'gemini-2.5-flash',
      history: history,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });
  }
  return chatSession;
};

export const resetChatSession = (history?: Content[]) => {
  chatSession = null;
  return getChatSession(history);
};

export const generateDailyVerse = async (): Promise<DailyVerse> => {
  try {
    const ai = getAiClient();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: "Give me a short, encouraging Bible verse for today. Return ONLY the JSON object with keys 'text' and 'reference'. Do not use Markdown code blocks.",
      config: {
        responseMimeType: 'application/json',
      }
    });

    const text = response.text;
    if (!text) throw new Error("No text returned");
    return JSON.parse(text) as DailyVerse;
  } catch (e) {
    console.error("Failed to fetch verse", e);
    return {
      text: "For I know the plans I have for you, declares the Lord, plans for welfare and not for evil, to give you a future and a hope.",
      reference: "Jeremiah 29:11"
    };
  }
};

export interface HoroscopeResult {
  text: string;
  sources: { uri: string; title: string }[];
}

export const generateHoroscope = async (sign: string): Promise<HoroscopeResult> => {
  try {
    const ai = getAiClient();
    const today = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash', // Using flash as tools are available
      contents: `Find the daily horoscope for ${sign} for today, ${today}. Provide a warm, encouraging message of the day based on the current astrological influences. Summarize the key themes for love, career, and personal growth. Use search to find accurate current information.`,
      config: {
        tools: [{ googleSearch: {} }], // Use Google Search to get current info
      }
    });

    const text = response.text;

    // Extract grounding sources as per guidelines
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources = chunks
      .map((c: any) => c.web)
      .filter((w: any) => w)
      .map((w: any) => ({ uri: w.uri, title: w.title }));

    if (!text) throw new Error("No text returned from horoscope generation");
    return { text, sources };
  } catch (e) {
    console.error("Failed to generate horoscope", e);
    return {
      text: "The stars are quiet today. Focus on your inner peace and trust in your journey.",
      sources: []
    };
  }
};

export const generateBibleImage = async (prompt: string, size: '1K' | '2K' | '4K' = '1K'): Promise<string | null> => {
  try {
    const ai = getAiClient();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview', // Gemini Pro Image
      contents: {
        parts: [{ text: `Create a high quality, respectful, biblical illustration for: ${prompt}. Artistic style: Realistic, cinematic lighting, detailed, oil painting style.` }]
      },
      config: {
        imageConfig: {
            imageSize: size
        }
      }
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
        }
      }
    }
    return null;
  } catch (e) {
    console.error("Failed to generate image", e);
    throw e;
  }
};

export const editBibleImage = async (imageDataUri: string, prompt: string, size: '1K' | '2K' | '4K' = '1K'): Promise<string | null> => {
  try {
    // Extract base64 data and mime type from data URI
    const match = imageDataUri.match(/^data:(.+);base64,(.+)$/);
    if (!match) throw new Error("Invalid image data");
    const mimeType = match[1];
    const data = match[2];

    const ai = getAiClient();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview', // Gemini Pro Image
      contents: {
        parts: [
          {
            inlineData: {
              data: data,
              mimeType: mimeType,
            },
          },
          {
            text: prompt,
          },
        ],
      },
      config: {
        imageConfig: {
            imageSize: size
        }
      }
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
        }
      }
    }
    return null;
  } catch (e) {
    console.error("Failed to edit image", e);
    throw e;
  }
};

import React, { useState, useRef } from 'react';
import { generateBibleImage, editBibleImage } from '../services/geminiService';
import { ImageIcon, SparklesIcon, XIcon, ArrowDownIcon, UploadIcon, WandIcon, EditIcon, PlusIcon, SettingsIcon } from './Icons';

type Mode = 'create' | 'edit';
type ImageSize = '1K' | '2K' | '4K';

export const BibleIllustrator: React.FC = () => {
  const [mode, setMode] = useState<Mode>('create');
  const [prompt, setPrompt] = useState('');
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [imageSize, setImageSize] = useState<ImageSize>('1K');

  // Edit Mode State
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    // Validation for Edit mode
    if (mode === 'edit' && !selectedImage) {
        setError("Please upload an image to edit first.");
        return;
    }

    // API Key Selection for Paid Model (Gemini Pro Image)
    try {
        if ((window as any).aistudio) {
            const hasKey = await (window as any).aistudio.hasSelectedApiKey();
            if (!hasKey) {
                await (window as any).aistudio.openSelectKey();
            }
        }
    } catch (e) {
        console.warn("API Key check skipped or failed", e);
    }

    setLoading(true);
    setError(null);
    setImageUrl(null);

    try {
      let result = null;

      if (mode === 'create') {
          result = await generateBibleImage(prompt, imageSize);
      } else {
          // Edit Mode
          if (selectedImage) {
             result = await editBibleImage(selectedImage, prompt, imageSize);
          }
      }

      if (result) {
        setImageUrl(result);
      } else {
        setError("Could not generate image. Please try again.");
      }
    } catch (e) {
      console.error(e);
      setError("An error occurred while creating the image.");
    } finally {
      setLoading(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.size > 5 * 1024 * 1024) {
          setError("Image size too large. Please use an image under 5MB.");
          return;
      }

      const reader = new FileReader();
      reader.onload = (event) => {
        if (event.target?.result) {
            setSelectedImage(event.target.result as string);
            setError(null);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleEditResult = () => {
    if (imageUrl) {
        setSelectedImage(imageUrl);
        setImageUrl(null);
        setPrompt('');
        setMode('edit');
    }
  };

  const clearSelectedImage = () => {
    setSelectedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative overflow-y-auto">
      {/* Header */}
      <div className="shrink-0 px-6 py-4 bg-white/80 backdrop-blur-md border-b border-brand-100 flex items-center justify-between z-10 sticky top-0">
        <span className="text-brand-800 font-display font-semibold tracking-wide text-lg">Bible Illustrator</span>
      </div>

      <div className="max-w-3xl mx-auto w-full px-6 py-8 pb-24">
        {/* Mode Switcher */}
        <div className="flex p-1 bg-white rounded-xl border border-brand-100 shadow-sm mb-6 max-w-sm mx-auto">
            <button 
                onClick={() => { setMode('create'); setError(null); }}
                className={`flex-1 flex items-center justify-center space-x-2 py-2 rounded-lg text-sm font-semibold transition-all ${mode === 'create' ? 'bg-brand-50 text-brand-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}
            >
                <SparklesIcon className="w-4 h-4" />
                <span>Create New</span>
            </button>
            <button 
                onClick={() => { setMode('edit'); setError(null); }}
                className={`flex-1 flex items-center justify-center space-x-2 py-2 rounded-lg text-sm font-semibold transition-all ${mode === 'edit' ? 'bg-brand-50 text-brand-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}
            >
                <WandIcon className="w-4 h-4" />
                <span>Edit Image</span>
            </button>
        </div>

        <div className="bg-white rounded-2xl p-6 shadow-sm border border-brand-100 mb-8">
            <div className="flex flex-wrap items-start justify-between mb-4 gap-4">
                <div className="flex items-center space-x-3">
                    <div className="p-2 bg-indigo-50 rounded-lg text-indigo-600">
                        <ImageIcon className="w-6 h-6" />
                    </div>
                    <div>
                        <h2 className="text-xl font-display font-bold text-slate-800">
                            {mode === 'create' ? "Bring Scripture to Life" : "Transform Your Image"}
                        </h2>
                        <p className="text-sm text-slate-500">
                            {mode === 'create' 
                                ? "Describe a biblical scene or enter a verse." 
                                : "Upload and modify an image with AI."}
                        </p>
                    </div>
                </div>

                {/* Size Selector */}
                <div className="flex items-center space-x-1 bg-slate-50 p-1 rounded-lg border border-slate-200">
                   {['1K', '2K', '4K'].map((size) => (
                      <button
                        key={size}
                        onClick={() => setImageSize(size as ImageSize)}
                        className={`px-3 py-1 text-xs font-bold rounded-md transition-all ${imageSize === size ? 'bg-white text-brand-700 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                      >
                        {size}
                      </button>
                   ))}
                </div>
            </div>

            {/* Edit Mode: Image Upload Area */}
            {mode === 'edit' && (
                <div className="mb-4 animate-in fade-in slide-in-from-top-4 duration-300">
                    {!selectedImage ? (
                        <div 
                            onClick={() => fileInputRef.current?.click()}
                            className="border-2 border-dashed border-brand-200 rounded-xl p-8 flex flex-col items-center justify-center cursor-pointer hover:bg-brand-50/50 transition-colors group"
                        >
                            <div className="w-12 h-12 bg-brand-50 rounded-full flex items-center justify-center mb-3 group-hover:scale-110 transition-transform text-brand-500">
                                <UploadIcon className="w-6 h-6" />
                            </div>
                            <p className="text-sm font-semibold text-brand-700">Click to upload an image</p>
                            <p className="text-xs text-slate-400 mt-1">Supports JPG, PNG (Max 5MB)</p>
                        </div>
                    ) : (
                        <div className="relative rounded-xl overflow-hidden bg-slate-100 border border-brand-100 group">
                            <img src={selectedImage} alt="Preview" className="w-full h-48 object-contain bg-slate-800/5" />
                            <button 
                                onClick={clearSelectedImage}
                                className="absolute top-2 right-2 p-1.5 bg-black/50 text-white rounded-full hover:bg-red-500 transition-colors"
                            >
                                <XIcon className="w-4 h-4" />
                            </button>
                        </div>
                    )}
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        onChange={handleImageUpload} 
                        accept="image/*" 
                        className="hidden" 
                    />
                </div>
            )}

            <div className="relative">
                <textarea 
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder={mode === 'create' 
                        ? "E.g., David facing Goliath in the valley, cinematic lighting..." 
                        : "E.g., Make it look like a watercolor painting, Add a dove in the sky..."}
                    rows={3}
                    className="w-full p-4 rounded-xl border border-brand-200 focus:border-brand-500 focus:ring-2 focus:ring-brand-100 outline-none bg-slate-50 resize-none text-slate-800 placeholder-slate-400"
                />
                <button 
                    onClick={handleGenerate}
                    disabled={loading || !prompt.trim() || (mode === 'edit' && !selectedImage)}
                    className="absolute bottom-3 right-3 px-4 py-2 bg-brand-600 text-white rounded-lg text-sm font-semibold hover:bg-brand-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center space-x-2 transition-all"
                >
                    {loading ? (
                        <>
                            <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                            <span>{mode === 'create' ? "Creating..." : "Editing..."}</span>
                        </>
                    ) : (
                        <>
                            {mode === 'create' ? <SparklesIcon className="w-4 h-4 text-yellow-300" /> : <WandIcon className="w-4 h-4 text-white" />}
                            <span>{mode === 'create' ? "Generate Art" : "Apply Edits"}</span>
                        </>
                    )}
                </button>
            </div>
            {error && <p className="mt-3 text-sm text-red-500 flex items-center"><XIcon className="w-4 h-4 mr-1" /> {error}</p>}
        </div>

        {/* Display Area */}
        {imageUrl ? (
            <div className="bg-white rounded-2xl p-4 shadow-lg border border-brand-100 animate-in fade-in duration-500">
                <div className="relative aspect-square md:aspect-video rounded-xl overflow-hidden bg-slate-100">
                    <img src={imageUrl} alt="Generated biblical illustration" className="w-full h-full object-cover" />
                </div>
                <div className="mt-4 flex flex-wrap justify-between items-center gap-3">
                    <div className="flex flex-col">
                        <p className="text-sm text-slate-500 italic truncate max-w-[200px] md:max-w-xs">"{prompt}"</p>
                        <span className="text-[10px] text-brand-400 font-bold uppercase">{imageSize} Resolution</span>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button 
                            onClick={handleEditResult}
                            className="flex items-center space-x-2 px-4 py-2 rounded-lg bg-brand-50 hover:bg-brand-100 text-brand-700 text-sm font-medium transition-colors"
                        >
                            <EditIcon className="w-4 h-4" />
                            <span>Edit This</span>
                        </button>
                        <a 
                            href={imageUrl} 
                            download={`lumen-illustration-${Date.now()}.png`}
                            className="flex items-center space-x-2 px-4 py-2 rounded-lg bg-slate-100 hover:bg-slate-200 text-slate-700 text-sm font-medium transition-colors"
                        >
                            <ArrowDownIcon className="w-4 h-4" />
                            <span>Download</span>
                        </a>
                    </div>
                </div>
            </div>
        ) : (
            !loading && (
                <div className="text-center py-12 opacity-50">
                    <ImageIcon className="w-16 h-16 mx-auto text-slate-300 mb-4" />
                    <p className="text-slate-500 font-medium">Your generated artwork will appear here.</p>
                </div>
            )
        )}

        {loading && !imageUrl && (
            <div className="text-center py-20">
                <div className="inline-block relative w-20 h-20">
                    <div className="absolute top-0 left-0 w-full h-full border-4 border-indigo-100 rounded-full"></div>
                    <div className="absolute top-0 left-0 w-full h-full border-4 border-indigo-500 rounded-full border-t-transparent animate-spin"></div>
                </div>
                <p className="mt-4 text-indigo-600 font-medium animate-pulse">{mode === 'create' ? "Painting your vision..." : "Applying your edits..."}</p>
                <p className="text-xs text-slate-400 mt-2">Powered by Gemini 3 Pro Image ({imageSize})</p>
            </div>
        )}
      </div>
    </div>
  );
};

