import React, { useState, useEffect } from 'react';
import { AccessibilityIcon, SunIcon, CheckIcon, XIcon, EyeIcon, PlayIcon, SpeakerIcon } from './Icons';
import { db } from '../services/firebase';
import { doc, setDoc, getDoc } from 'firebase/firestore';

interface AccessibilitySettingsProps {
  userId: string;
}

export const AccessibilitySettings: React.FC<AccessibilitySettingsProps> = ({ userId }) => {
  const [settings, setSettings] = useState({
    textSize: 16,
    highContrast: false,
    reducedMotion: false,
    voiceURI: '',
  });

  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [message, setMessage] = useState<{type: 'success'|'error', text: string} | null>(null);

  useEffect(() => {
    // Apply settings in real-time for preview
    document.documentElement.style.fontSize = `${settings.textSize}px`;

    if (settings.highContrast) document.body.classList.add('high-contrast');
    else document.body.classList.remove('high-contrast');

    if (settings.reducedMotion) document.body.classList.add('reduced-motion');
    else document.body.classList.remove('reduced-motion');

  }, [settings]);

  // Load Voices
  useEffect(() => {
    const loadVoices = () => {
        const available = window.speechSynthesis.getVoices();
        // Filter for English and take top 10 to satisfy "10 different options" request
        // Prioritize local voices if possible
        const englishVoices = available.filter(v => v.lang.includes('en'));
        setVoices(englishVoices.slice(0, 10));
    };

    loadVoices();
    window.speechSynthesis.onvoiceschanged = loadVoices;

    return () => { window.speechSynthesis.onvoiceschanged = null; };
  }, []);

  useEffect(() => {
    if (!userId) return;

    if (userId === 'guest-dev-user') {
        const saved = localStorage.getItem('lumen_user_profile');
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                setSettings(prev => ({
                    textSize: parsed.textSize || 16,
                    highContrast: parsed.highContrast || false,
                    reducedMotion: parsed.reducedMotion || false,
                    voiceURI: parsed.voiceURI || '',
                }));
            } catch (e) { console.error("Error parsing profile", e); }
        }
        return;
    }

    if (!db) return;

    const fetchSettings = async () => {
      try {
        const docRef = doc(db, 'users', userId);
        const docSnap = await getDoc(docRef);
        if (docSnap.exists()) {
            const data = docSnap.data();
            setSettings(prev => ({
                textSize: data.textSize || 16,
                highContrast: data.highContrast || false,
                reducedMotion: data.reducedMotion || false,
                voiceURI: data.voiceURI || '',
            }));
        }
      } catch (e) {
        console.error("Error fetching accessibility settings", e);
      }
    };
    fetchSettings();
  }, [userId]);

  const handleSave = async () => {
    setIsSaving(true);
    setMessage(null);
    try {
      if (userId === 'guest-dev-user') {
          const local = localStorage.getItem('lumen_user_profile');
          const profile = local ? JSON.parse(local) : {};
          const updatedProfile = { ...profile, ...settings };
          localStorage.setItem('lumen_user_profile', JSON.stringify(updatedProfile));
          setMessage({ type: 'success', text: 'Settings updated locally.' });
      } else {
          if (!db) throw new Error("Database connection unavailable.");
          await setDoc(doc(db, 'users', userId), settings, { merge: true });
          setMessage({ type: 'success', text: 'Accessibility settings saved.' });
      }
    } catch (e) {
      console.error("Error saving settings", e);
      setMessage({ type: 'error', text: 'Failed to save settings.' });
    } finally {
      setIsSaving(false);
    }
  };

  const handlePreviewVoice = (uri: string) => {
      window.speechSynthesis.cancel();
      const voice = voices.find(v => v.voiceURI === uri);
      if (voice) {
          const utterance = new SpeechSynthesisUtterance("Hello! I am Lumen, your spiritual companion.");
          utterance.voice = voice;
          window.speechSynthesis.speak(utterance);
      }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative overflow-y-auto">
       <div className="shrink-0 px-6 py-4 bg-white/80 backdrop-blur-md border-b border-brand-100 flex items-center justify-between z-10 sticky top-0">
          <span className="text-brand-800 font-display font-semibold tracking-wide text-lg">Accessibility</span>
       </div>

       <div className="max-w-2xl mx-auto w-full px-6 py-8 pb-20">
          {message && (
            <div role="alert" className={`mb-6 p-4 rounded-xl border text-sm font-medium flex items-center ${message.type === 'success' ? 'bg-green-50 border-green-100 text-green-600' : 'bg-red-50 border-red-100 text-red-600'}`}>
                {message.type === 'success' ? <CheckIcon className="w-5 h-5 mr-2" /> : <XIcon className="w-5 h-5 mr-2" />}
                {message.text}
            </div>
          )}

           <div className="bg-white rounded-2xl p-6 shadow-sm border border-brand-100 space-y-8">
              <div className="flex items-center text-slate-800 font-display font-semibold border-b border-slate-50 pb-2 mb-4">
                <AccessibilityIcon className="w-5 h-5 mr-2 text-brand-500" />
                Display Settings
              </div>

              {/* Text Size */}
              <div>
                  <label htmlFor="textSize" className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Text Size</label>
                  <input 
                    id="textSize"
                    type="range" 
                    min="14" max="24" step="1"
                    value={settings.textSize}
                    onChange={(e) => setSettings(s => ({...s, textSize: parseInt(e.target.value)}))}
                    className="w-full accent-brand-600 h-2 bg-slate-100 rounded-lg appearance-none cursor-pointer"
                  />
                  <div className="flex justify-between text-xs text-slate-400 mt-2 font-medium">
                      <span>Small (14px)</span>
                      <span>Default (16px)</span>
                      <span>Large (24px)</span>
                  </div>
                  <div className="mt-4 p-4 bg-slate-50 rounded-xl text-center">
                    <p className="text-slate-700">The quick brown fox jumps over the lazy dog.</p>
                  </div>
              </div>

              {/* High Contrast */}
              <div className="flex items-center justify-between py-2">
                 <div className="flex items-center space-x-3">
                    <div className="p-2 bg-slate-100 rounded-lg text-slate-600">
                        <EyeIcon className="w-5 h-5" />
                    </div>
                    <div>
                        <h4 className="font-semibold text-slate-800">High Contrast Mode</h4>
                        <p className="text-xs text-slate-500">Increase contrast for better legibility.</p>
                    </div>
                 </div>
                 <label className="relative inline-flex items-center cursor-pointer">
                    <input type="checkbox" className="sr-only peer" checked={settings.highContrast} onChange={(e) => setSettings(s => ({...s, highContrast: e.target.checked}))} />
                    <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none peer-focus:ring-2 peer-focus:ring-brand-300 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-brand-600"></div>
                 </label>
              </div>

              {/* Reduced Motion */}
              <div className="flex items-center justify-between py-2">
                 <div className="flex items-center space-x-3">
                    <div className="p-2 bg-slate-100 rounded-lg text-slate-600">
                        <PlayIcon className="w-5 h-5" />
                    </div>
                    <div>
                        <h4 className="font-semibold text-slate-800">Reduced Motion</h4>
                        <p className="text-xs text-slate-500">Disable animations and transitions.</p>
                    </div>
                 </div>
                 <label className="relative inline-flex items-center cursor-pointer">
                    <input type="checkbox" className="sr-only peer" checked={settings.reducedMotion} onChange={(e) => setSettings(s => ({...s, reducedMotion: e.target.checked}))} />
                    <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none peer-focus:ring-2 peer-focus:ring-brand-300 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-brand-600"></div>
                 </label>
              </div>

              <div className="border-t border-slate-100 pt-8">
                 <div className="flex items-center text-slate-800 font-display font-semibold border-b border-slate-50 pb-2 mb-4">
                    <SpeakerIcon className="w-5 h-5 mr-2 text-brand-500" />
                    Audio Settings
                  </div>

                 <div>
                    <label htmlFor="voiceSelect" className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">AI Voice Preference</label>
                    <div className="flex space-x-2">
                        <select 
                            id="voiceSelect" 
                            value={settings.voiceURI}
                            onChange={(e) => setSettings(s => ({...s, voiceURI: e.target.value}))}
                            className="flex-1 px-4 py-2 rounded-xl border border-slate-200 bg-white text-slate-700 focus:border-brand-500 focus:ring-2 focus:ring-brand-200 outline-none"
                        >
                            <option value="">Default System Voice</option>
                            {voices.map(voice => (
                                <option key={voice.voiceURI} value={voice.voiceURI}>
                                    {voice.name}
                                </option>
                            ))}
                        </select>
                        <button 
                            type="button"
                            onClick={() => handlePreviewVoice(settings.voiceURI)}
                            disabled={!settings.voiceURI}
                            className="p-2 rounded-xl bg-slate-100 hover:bg-slate-200 text-slate-600 disabled:opacity-50"
                            title="Preview Voice"
                        >
                            <PlayIcon className="w-5 h-5" />
                        </button>
                    </div>
                    <p className="text-xs text-slate-400 mt-2">Select one of 10 available English voices for Lumen to speak with.</p>
                 </div>
              </div>

              <button 
                  onClick={handleSave}
                  disabled={isSaving}
                  className="w-full py-3.5 rounded-xl font-semibold shadow-md transition-all bg-brand-600 text-white hover:bg-brand-700 disabled:opacity-70 mt-6"
                >
                  {isSaving ? 'Saving...' : 'Save Settings'}
               </button>
           </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GenerateContentResponse, Content } from "@google/genai";
import { getChatSession, resetChatSession } from '../services/geminiService';
import { Message, Role } from '../types';
import { SendIcon, RefreshIcon, DoveIcon, BookIcon, HeartIcon, ShareIcon, CheckIcon, SpeakerIcon, StopIcon, CopyIcon } from './Icons';
import { DailyVerseCard } from './DailyVerseCard';
import { db } from '../services/firebase';
import { collection, doc, setDoc, getDoc, addDoc } from 'firebase/firestore';
import { ShareModal } from './ShareModal';

interface ChatProps {
  userId: string;
  initialPrompt?: string;
  onClearInitialPrompt?: () => void;
}

const findBibleReference = (text: string): string | null => {
  const regex = /\b((?:1|2|3|I|II|III)\s?)?[A-Z][a-z]+\.?\s\d+(?::\d+(?:-\d+)?)?\b/;
  const match = text.match(regex);
  return match ? match[0] : null;
};

export const Chat: React.FC<ChatProps> = ({ userId, initialPrompt, onClearInitialPrompt }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const [sharingMessage, setSharingMessage] = useState<{text: string, id: string} | null>(null);
  const [preferredVoice, setPreferredVoice] = useState<string>('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const hasLoadedHistory = useRef(false);

  // Load User Preferences (Voice)
  useEffect(() => {
    const fetchPreferences = async () => {
        if (!userId) return;

        let voice = '';
        if (userId === 'guest-dev-user') {
            const saved = localStorage.getItem('lumen_user_profile');
            if (saved) {
                try {
                    const parsed = JSON.parse(saved);
                    voice = parsed.voiceURI || '';
                } catch (e) {}
            }
        } else if (db) {
            try {
                const docRef = doc(db, 'users', userId);
                const docSnap = await getDoc(docRef);
                if (docSnap.exists()) {
                    voice = docSnap.data().voiceURI || '';
                }
            } catch (e) {}
        }
        setPreferredVoice(voice);
    };
    fetchPreferences();
  }, [userId]);

  // Load history
  useEffect(() => {
    const loadHistory = async () => {
      try {
        if (userId === 'guest-dev-user') {
          const saved = localStorage.getItem('lumen_chat_history');
          if (saved) {
             const savedMessages = JSON.parse(saved);
             setMessages(savedMessages);
             const history: Content[] = savedMessages
               .filter((m: Message) => m.id !== 'welcome' && !m.isStreaming)
               .map((m: Message) => ({
                 role: m.role,
                 parts: [{ text: m.text }]
               }));
             getChatSession(history);
          } else {
             // Default for guest
             const welcomeMsg: Message = { id: 'welcome', role: Role.MODEL, text: "Welcome. I am Lumen. How can I support your spiritual journey today?", timestamp: Date.now() };
             setMessages([welcomeMsg]);
             getChatSession([]);
          }
          hasLoadedHistory.current = true;
          return;
        }

        if (db) {
            const docRef = doc(db, 'users', userId, 'chats', 'main');
            const docSnap = await getDoc(docRef);
            if (docSnap.exists()) {
              const savedMessages = docSnap.data().messages as Message[];
              setMessages(savedMessages);

              // Restore Gemini context
              const history: Content[] = savedMessages
                .filter(m => m.id !== 'welcome' && !m.isStreaming)
                .map(m => ({
                  role: m.role,
                  parts: [{ text: m.text }]
                }));
              getChatSession(history);
            } else {
              // Default Welcome
              const welcomeMsg: Message = {
                id: 'welcome',
                role: Role.MODEL,
                text: "Welcome. I am Lumen. How can I support your spiritual journey today?",
                timestamp: Date.now(),
              };
              setMessages([welcomeMsg]);
              getChatSession([]);
            }
        } else {
             const welcomeMsg: Message = { id: 'welcome', role: Role.MODEL, text: "Welcome. I am Lumen. How can I support your spiritual journey today?", timestamp: Date.now() };
             setMessages([welcomeMsg]);
             getChatSession([]);
        }
      } catch (e) {
        console.error("Error loading chat history", e);
        setMessages([{ id: 'welcome', role: Role.MODEL, text: "Welcome. I am Lumen. How can I support your spiritual journey today?", timestamp: Date.now() }]);
      } finally {
        hasLoadedHistory.current = true;
      }
    };

    if (userId) loadHistory();
  }, [userId]);

  // Save history
  useEffect(() => {
    if (!hasLoadedHistory.current || messages.length === 0) return;
    const saveHistory = async () => {
        try {
            if (userId === 'guest-dev-user') {
                localStorage.setItem('lumen_chat_history', JSON.stringify(messages));
            } else if (db) {
                await setDoc(doc(db, 'users', userId, 'chats', 'main'), { messages });
            }
        } catch (e) { console.error("Error saving chat", e); }
    };
    const timeout = setTimeout(saveHistory, 1000);
    return () => clearTimeout(timeout);
  }, [messages, userId]);

  // Cleanup speech on unmount
  useEffect(() => {
    return () => window.speechSynthesis.cancel();
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = useCallback(async (text: string) => {
    if (!text.trim() || isLoading) return;

    // Stop speaking if new message is sent
    window.speechSynthesis.cancel();
    setSpeakingId(null);

    const userMsg: Message = {
      id: Date.now().toString(),
      role: Role.USER,
      text: text,
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const chat = getChatSession();

      const botMsgId = (Date.now() + 1).toString();
      setMessages(prev => [
        ...prev,
        {
          id: botMsgId,
          role: Role.MODEL,
          text: '',
          isStreaming: true,
          timestamp: Date.now(),
        }
      ]);

      const result = await chat.sendMessageStream({ message: text });
      let fullText = '';

      for await (const chunk of result) {
        const chunkText = (chunk as GenerateContentResponse).text || '';
        fullText += chunkText;
        setMessages(prev => prev.map(msg => msg.id === botMsgId ? { ...msg, text: fullText } : msg));
      }

      setMessages(prev => prev.map(msg => msg.id === botMsgId ? { ...msg, isStreaming: false } : msg));

    } catch (error) {
      console.error("Error sending message:", error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: Role.MODEL, text: "I apologize, but I am having trouble connecting right now.", timestamp: Date.now() }]);
    } finally {
      setIsLoading(false);
    }
  }, [isLoading]);

  useEffect(() => {
    if (initialPrompt && hasLoadedHistory.current) {
      handleSend(initialPrompt);
      if(onClearInitialPrompt) onClearInitialPrompt();
    }
  }, [initialPrompt, hasLoadedHistory.current]);

  const handleReset = async () => {
    if(window.confirm("Clear chat history?")) {
        window.speechSynthesis.cancel();
        setSpeakingId(null);
        resetChatSession();
        const welcomeMsg = {
            id: Date.now().toString(),
            role: Role.MODEL,
            text: "Chat cleared. How may I help you anew?",
            timestamp: Date.now(),
        };
        setMessages([welcomeMsg]);
        if (userId === 'guest-dev-user') {
            localStorage.setItem('lumen_chat_history', JSON.stringify([welcomeMsg]));
        } else if (db) {
            await setDoc(doc(db, 'users', userId, 'chats', 'main'), { messages: [welcomeMsg] });
        }
    }
  };

  const handleRegenerate = async () => {
    if (isLoading || messages.length < 2) return;

    // Find last message and check if it's from model
    const lastMsg = messages[messages.length - 1];
    if (lastMsg.role !== Role.MODEL) return;

    // Find the user message before it
    const userMsg = messages[messages.length - 2];
    if (!userMsg || userMsg.role !== Role.USER) return;

    // Stop any speech
    window.speechSynthesis.cancel();
    setSpeakingId(null);

    // Remove both the last model response and the user message (handleSend will re-add user message)
    const keptMessages = messages.slice(0, -2);
    setMessages(keptMessages);

    // Re-initialize session with history up to that point
    const history = keptMessages
      .filter(m => m.id !== 'welcome' && !m.isStreaming)
      .map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

    resetChatSession(history);

    // Resend the user's last message
    await handleSend(userMsg.text);
  };

  const handleSaveVerse = async (text: string, reference: string) => {
      const newFav = {
          reference: reference,
          text: text, // Saving the full context for now, ideally AI would parse just the verse text
          date: Date.now(),
          source: 'chat'
      };

      try {
        if (userId === 'guest-dev-user') {
            const local = localStorage.getItem('lumen_favorites');
            const favs = local ? JSON.parse(local) : [];
            favs.unshift({ ...newFav, id: Date.now().toString() });
            localStorage.setItem('lumen_favorites', JSON.stringify(favs));
        } else if (db) {
            await addDoc(collection(db, 'users', userId, 'favorites'), newFav);
        }
        alert("Verse saved to favorites!");
      } catch (e) {
        console.error("Error saving favorite", e);
      }
  };

  const handleCopy = async (text: string, id: string) => {
    try {
      await navigator.clipboard.writeText(text);
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    } catch (err) {
      console.error('Failed to copy text', err);
    }
  };

  const handleSpeak = (text: string, id: string) => {
      if (speakingId === id) {
          window.speechSynthesis.cancel();
          setSpeakingId(null);
      } else {
          window.speechSynthesis.cancel(); // Cancel any current speech
          const utterance = new SpeechSynthesisUtterance(text);

          if (preferredVoice) {
              const voices = window.speechSynthesis.getVoices();
              const voice = voices.find(v => v.voiceURI === preferredVoice);
              if (voice) utterance.voice = voice;
          }

          utterance.onend = () => setSpeakingId(null);
          utterance.onerror = () => setSpeakingId(null);
          window.speechSynthesis.speak(utterance);
          setSpeakingId(id);
      }
  };

  return (
    <div className="flex flex-col h-full relative">
      {/* Chat Header */}
      <div className="shrink-0 px-6 py-4 bg-white/80 backdrop-blur-md border-b border-brand-100 flex justify-between items-center z-10">
        <div className="flex items-center space-x-3">
          <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse" aria-hidden="true"></div>
          <span className="text-brand-800 font-display font-semibold tracking-wide">Lumen Companion</span>
        </div>
        <button 
            onClick={handleReset} 
            className="p-2 text-brand-400 hover:text-brand-600 transition-colors rounded-full hover:bg-brand-50"
            aria-label="Start New Chat"
            title="Reset Chat"
        >
          <RefreshIcon className="w-5 h-5" />
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 sm:p-6 pb-32" aria-live="polite">
        <div className="max-w-3xl mx-auto space-y-6">
          <DailyVerseCard userId={userId} />
          {messages.map((msg, index) => {
            const reference = msg.role === Role.MODEL && !msg.isStreaming ? findBibleReference(msg.text) : null;
            const isLastMessage = index === messages.length - 1;

            return (
            <div key={msg.id} className={`flex w-full ${msg.role === Role.USER ? 'justify-end' : 'justify-start items-end'}`}>
              {msg.role === Role.MODEL && (
                <div className="flex-shrink-0 mr-2.5 mb-1" aria-hidden="true">
                  <div className="w-8 h-8 rounded-full bg-gradient-to-br from-brand-100 to-white border border-brand-200 flex items-center justify-center shadow-sm text-brand-500">
                    <DoveIcon className="w-4 h-4" />
                  </div>
                </div>
              )}
              <div className={`max-w-[90%] sm:max-w-[80%] rounded-2xl px-5 py-4 shadow-sm leading-relaxed ${msg.role === Role.USER ? 'bg-brand-600 text-white rounded-br-none' : 'bg-gradient-to-br from-white to-brand-50 text-slate-700 rounded-bl-none border border-brand-100 group relative'}`}>
                <div className="whitespace-pre-wrap font-sans text-[15px] sm:text-[16px]">
                  {msg.text}

                  {/* Streaming Cursor for content */}
                  {msg.isStreaming && msg.text.length > 0 && (
                    <span className="inline-block w-1.5 h-4 ml-0.5 align-middle bg-brand-400/80 animate-pulse rounded-[1px]"></span>
                  )}

                  {/* Thinking Indicator for initial load */}
                  {msg.isStreaming && msg.text.length === 0 && (
                    <div className="flex space-x-1 items-center h-6 my-1" aria-label="Thinking">
                      <div className="w-1.5 h-1.5 bg-brand-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                      <div className="w-1.5 h-1.5 bg-brand-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                      <div className="w-1.5 h-1.5 bg-brand-400 rounded-full animate-bounce"></div>
                    </div>
                  )}
                </div>

                {/* Actions Footer - Only for completed model messages */}
                {msg.role === Role.MODEL && !msg.isStreaming && (
                  <div className="mt-3 pt-3 border-t border-brand-100/50 flex flex-wrap gap-2 items-center justify-between">
                    {/* Left: Reference Actions */}
                    <div>
                      {reference && (
                        <button onClick={() => handleSend(`Read surrounding verses for ${reference}`)} className="flex items-center space-x-1.5 px-3 py-1.5 bg-white/60 hover:bg-white rounded-lg text-xs font-medium text-brand-700 transition-colors border border-brand-100 shadow-sm">
                          <BookIcon className="w-3.5 h-3.5 text-brand-400" />
                          <span>Read Context</span>
                        </button>
                      )}
                    </div>

                    {/* Right: Actions */}
                    <div className="flex items-center space-x-2">
                       {/* Regenerate Button - Only on last message */}
                       {isLastMessage && (
                           <button 
                              onClick={handleRegenerate}
                              className="flex items-center space-x-1 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-brand-600 transition-colors hover:bg-white/60"
                              aria-label="Regenerate response"
                              title="Regenerate"
                           >
                              <RefreshIcon className="w-4 h-4" />
                              <span className="hidden sm:inline">Regenerate</span>
                           </button>
                       )}

                       {/* Read Aloud Button */}
                       <button
                          onClick={() => handleSpeak(msg.text, msg.id)}
                          className="flex items-center space-x-1 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-brand-600 transition-colors hover:bg-white/60"
                          aria-label={speakingId === msg.id ? "Stop reading" : "Read aloud"}
                          title={speakingId === msg.id ? "Stop reading" : "Read aloud"}
                       >
                          {speakingId === msg.id ? <StopIcon className="w-4 h-4 text-brand-600 animate-pulse" /> : <SpeakerIcon className="w-4 h-4" />}
                          <span className="hidden sm:inline">{speakingId === msg.id ? 'Stop' : 'Listen'}</span>
                       </button>

                       {reference && (
                        <button 
                            onClick={() => handleSaveVerse(msg.text, reference)}
                            className="flex items-center space-x-1 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-red-500 transition-colors hover:bg-white/60"
                            aria-label="Save verse"
                            title="Save verse"
                        >
                            <HeartIcon className="w-4 h-4" />
                            <span className="hidden sm:inline">Save</span>
                        </button>
                       )}

                       <button 
                          onClick={() => handleCopy(msg.text, msg.id)}
                          className="flex items-center space-x-1 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-brand-600 transition-colors hover:bg-white/60"
                          aria-label="Copy text"
                          title="Copy text"
                       >
                          {copiedId === msg.id ? <CheckIcon className="w-4 h-4 text-green-500" /> : <CopyIcon className="w-4 h-4" />}
                          <span className="hidden sm:inline">{copiedId === msg.id ? 'Copied' : 'Copy'}</span>
                       </button>

                       <button 
                          onClick={() => setSharingMessage({ text: msg.text, id: msg.id })}
                          className="flex items-center space-x-1 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-brand-600 transition-colors hover:bg-white/60"
                          aria-label="Share message"
                          title="Share"
                       >
                          <ShareIcon className="w-4 h-4" />
                          <span className="hidden sm:inline">Share</span>
                       </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          )})}
          <div ref={messagesEndRef} />
        </div>
      </div>

      {/* Input Area */}
      <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-slate-50 via-slate-50 to-transparent">
        <div className="max-w-3xl mx-auto bg-white rounded-2xl shadow-xl border border-brand-100 p-2 flex items-end space-x-2 ring-1 ring-brand-100/50">
          <label htmlFor="chatInput" className="sr-only">Type your message</label>
          <textarea
            id="chatInput"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(input); }}}
            placeholder="Ask a question..."
            className="flex-1 max-h-32 min-h-[52px] bg-transparent border-none focus:ring-0 text-slate-800 placeholder-slate-400 resize-none p-3"
            rows={1}
          />
          <button 
            onClick={() => handleSend(input)} 
            disabled={!input.trim() || isLoading} 
            className={`p-3 rounded-xl flex-shrink-0 transition-all duration-200 ${input.trim() && !isLoading ? 'bg-brand-600 text-white shadow-md hover:bg-brand-700' : 'bg-slate-100 text-slate-400 cursor-not-allowed'}`}
            aria-label="Send Message"
          >
            <SendIcon className="w-5 h-5" />
          </button>
        </div>
      </div>

      <ShareModal 
        isOpen={!!sharingMessage} 
        onClose={() => setSharingMessage(null)} 
        text={sharingMessage?.text || ''} 
      />
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { generateDailyVerse } from '../services/geminiService';
import { DailyVerse } from '../types';
import { HeartIcon, SpeakerIcon, StopIcon, ShareIcon } from './Icons';
import { db } from '../services/firebase';
import { collection, addDoc, query, where, getDocs, deleteDoc, doc, getDoc } from 'firebase/firestore';
import { ShareModal } from './ShareModal';

interface DailyVerseCardProps {
  userId: string;
}

export const DailyVerseCard: React.FC<DailyVerseCardProps> = ({ userId }) => {
  const [verse, setVerse] = useState<DailyVerse | null>(null);
  const [loading, setLoading] = useState(true);
  const [isSaved, setIsSaved] = useState(false);
  const [saving, setSaving] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [showShare, setShowShare] = useState(false);
  const [preferredVoice, setPreferredVoice] = useState<string>('');

  // Check if current user (or guest) has this verse saved
  const checkSavedStatus = async (verseRef: string) => {
    if (!userId) return;

    if (userId === 'guest-dev-user') {
       const local = localStorage.getItem('lumen_favorites');
       if (local) {
           const favs = JSON.parse(local);
           const exists = favs.some((f: any) => f.reference === verseRef);
           setIsSaved(exists);
       }
    } else {
        if (!db) return;
        try {
          const q = query(collection(db, 'users', userId, 'favorites'), where('reference', '==', verseRef));
          const snapshot = await getDocs(q);
          setIsSaved(!snapshot.empty);
        } catch (e) {
          console.error("Error checking saved status", e);
        }
    }
  };

  // Load Preferences
  useEffect(() => {
    const fetchPreferences = async () => {
        if (!userId) return;

        let voice = '';
        if (userId === 'guest-dev-user') {
            const saved = localStorage.getItem('lumen_user_profile');
            if (saved) {
                try {
                    const parsed = JSON.parse(saved);
                    voice = parsed.voiceURI || '';
                } catch (e) {}
            }
        } else if (db) {
            try {
                const docRef = doc(db, 'users', userId);
                const docSnap = await getDoc(docRef);
                if (docSnap.exists()) {
                    voice = docSnap.data().voiceURI || '';
                }
            } catch (e) {}
        }
        setPreferredVoice(voice);
    };
    fetchPreferences();
  }, [userId]);

  useEffect(() => {
    let mounted = true;
    const fetchVerse = async () => {
      const v = await generateDailyVerse();
      if (mounted) {
        setVerse(v);
        setLoading(false);
        checkSavedStatus(v.reference);
      }
    };
    fetchVerse();

    // Cleanup speech on unmount
    return () => { 
        mounted = false; 
        window.speechSynthesis.cancel();
    };
  }, [userId]);

  const handleToggleSave = async () => {
    if (!verse || saving || !userId) return;
    setSaving(true);

    try {
        if (isSaved) {
            // Remove
            if (userId === 'guest-dev-user') {
                const local = localStorage.getItem('lumen_favorites');
                if (local) {
                    const favs = JSON.parse(local);
                    const updated = favs.filter((f: any) => f.reference !== verse.reference);
                    localStorage.setItem('lumen_favorites', JSON.stringify(updated));
                }
            } else if (db) {
                const q = query(collection(db, 'users', userId, 'favorites'), where('reference', '==', verse.reference));
                const snapshot = await getDocs(q);
                snapshot.forEach(async (d) => {
                    await deleteDoc(d.ref);
                });
            }
            setIsSaved(false);
        } else {
            // Save
            const newFav = {
                reference: verse.reference,
                text: verse.text,
                date: Date.now(),
                source: 'daily'
            };

            if (userId === 'guest-dev-user') {
                 const local = localStorage.getItem('lumen_favorites');
                 const favs = local ? JSON.parse(local) : [];
                 favs.unshift({ ...newFav, id: Date.now().toString() });
                 localStorage.setItem('lumen_favorites', JSON.stringify(favs));
            } else if (db) {
                await addDoc(collection(db, 'users', userId, 'favorites'), newFav);
            }
            setIsSaved(true);
        }
    } catch (e) {
        console.error("Error toggling favorite", e);
    } finally {
        setSaving(false);
    }
  };

  const handleSpeak = () => {
    if (!verse) return;

    if (isSpeaking) {
        window.speechSynthesis.cancel();
        setIsSpeaking(false);
    } else {
        window.speechSynthesis.cancel(); // Cancel any existing speech
        const utterance = new SpeechSynthesisUtterance(`${verse.text}. ${verse.reference}`);

        if (preferredVoice) {
            const voices = window.speechSynthesis.getVoices();
            const voice = voices.find(v => v.voiceURI === preferredVoice);
            if (voice) utterance.voice = voice;
        }

        utterance.onend = () => setIsSpeaking(false);
        utterance.onerror = () => setIsSpeaking(false);
        window.speechSynthesis.speak(utterance);
        setIsSpeaking(true);
    }
  };

  if (loading) {
    return (
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-brand-100 animate-pulse h-48 flex items-center justify-center" aria-label="Loading daily verse">
        <div className="text-brand-300 text-sm">Seeking wisdom...</div>
      </div>
    );
  }

  return (
    <div className="relative overflow-hidden bg-gradient-to-br from-white to-brand-50 rounded-2xl p-8 shadow-md border border-brand-100 group hover:shadow-lg transition-shadow duration-300">
      <div className="absolute top-0 right-0 -mr-8 -mt-8 w-24 h-24 bg-gold-400/10 rounded-full blur-2xl"></div>

      {/* Actions Top Right */}
      <div className="absolute top-4 right-4 flex space-x-1 z-20">
        <button 
            onClick={handleSpeak}
            className={`p-2 rounded-full transition-colors ${isSpeaking ? 'text-brand-600 bg-brand-50 ring-2 ring-brand-100' : 'text-slate-300 hover:text-brand-500 hover:bg-white/50'}`}
            aria-label={isSpeaking ? "Stop reading verse" : "Read verse aloud"}
            title={isSpeaking ? "Stop" : "Listen"}
        >
            {isSpeaking ? <StopIcon className="w-6 h-6 animate-pulse" /> : <SpeakerIcon className="w-6 h-6" />}
        </button>
        <button 
            onClick={() => setShowShare(true)}
            className="p-2 rounded-full text-slate-300 hover:text-brand-500 hover:bg-white/50 transition-colors"
            aria-label="Share verse"
            title="Share"
        >
            <ShareIcon className="w-6 h-6" />
        </button>
        <button 
            onClick={handleToggleSave}
            className="p-2 rounded-full hover:bg-white/50 transition-colors"
            aria-label={isSaved ? "Remove from favorites" : "Save to favorites"}
            title={isSaved ? "Remove from favorites" : "Save to favorites"}
        >
            <HeartIcon className={`w-6 h-6 transition-colors ${isSaved ? 'text-red-500' : 'text-slate-300 hover:text-red-400'}`} filled={isSaved} />
        </button>
      </div>

      <div className="relative z-10 text-center">
        <h3 className="text-xs font-bold uppercase tracking-widest text-brand-400 mb-4">Verse of the Day</h3>
        <p className="font-serif text-xl md:text-2xl text-slate-800 italic leading-relaxed mb-4">
          "{verse?.text}"
        </p>
        <div className="flex justify-center items-center space-x-2">
          <div className="h-px w-8 bg-gold-400"></div>
          <p className="text-sm font-semibold text-brand-700">{verse?.reference}</p>
          <div className="h-px w-8 bg-gold-400"></div>
        </div>
      </div>

      {/* Share Modal */}
      <ShareModal 
        isOpen={showShare} 
        onClose={() => setShowShare(false)} 
        text={`"${verse?.text}" - ${verse?.reference}`} 
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { LogOutIcon, UserIcon, CheckIcon, XIcon, SunIcon, TrashIcon, ShieldIcon } from './Icons';
import { UserProfile } from '../types';
import { db, deleteUserData } from '../services/firebase';
import { doc, setDoc, getDoc } from 'firebase/firestore';

interface ProfileSettingsProps {
  userId: string;
  userEmail: string | null;
  onLogout: () => void;
}

export const ProfileSettings: React.FC<ProfileSettingsProps> = ({ userId, userEmail, onLogout }) => {
  const [profile, setProfile] = useState<UserProfile>({
    firstName: '',
    lastName: '',
    email: userEmail || '',
    dateOfBirth: '',
    jobTitle: '',
    onlineStatus: 'Online',
    bio: '',
    passwordHistory: []
  });

  const [isSaving, setIsSaving] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [message, setMessage] = useState<{type: 'success'|'error', text: string} | null>(null);

  const isGuest = userId === 'guest-dev-user';

  useEffect(() => {
    if (!userId) return;

    // Guest Mode: Load from Local Storage
    if (userId === 'guest-dev-user') {
        const saved = localStorage.getItem('lumen_user_profile');
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                setProfile(prev => ({ ...prev, ...parsed, email: userEmail || '' }));
            } catch (e) { console.error("Error parsing profile", e); }
        }
        return;
    }

    if (!db) return;

    const fetchProfile = async () => {
      try {
        const docRef = doc(db, 'users', userId);
        const docSnap = await getDoc(docRef);
        if (docSnap.exists()) {
            const data = docSnap.data() as UserProfile;
            setProfile(prev => ({ ...prev, ...data }));
        }
      } catch (e) {
        console.error("Error fetching profile", e);
      }
    };
    fetchProfile();
  }, [userId, userEmail]);

  const handleSave = async () => {
    setIsSaving(true);
    setMessage(null);
    try {
      if (userId === 'guest-dev-user') {
          const current = localStorage.getItem('lumen_user_profile');
          const currentObj = current ? JSON.parse(current) : {};
          localStorage.setItem('lumen_user_profile', JSON.stringify({ ...currentObj, ...profile }));
          setMessage({ type: 'success', text: 'Profile updated locally (Guest Mode).' });
      } else {
          if (!db) throw new Error("Database connection unavailable.");
          await setDoc(doc(db, 'users', userId), profile, { merge: true });
          setMessage({ type: 'success', text: 'Profile updated successfully.' });
      }
    } catch (e) {
      console.error("Error saving profile", e);
      setMessage({ type: 'error', text: 'Failed to update profile.' });
    } finally {
      setIsSaving(false);
    }
  };

  const handleDeleteAccount = async () => {
    // Guest User: Immediate local cleanup
    if (userId === 'guest-dev-user') {
        if (!window.confirm("Are you sure you want to delete your guest session? This will immediately remove all local data.")) {
            return;
        }

        setIsDeleting(true);
        try {
            localStorage.removeItem('lumen_user_profile');
            localStorage.removeItem('lumen_chat_history');
            localStorage.removeItem('lumen_favorites');
            localStorage.removeItem('lumen_prayers');
            localStorage.removeItem('lumen_logs');
            localStorage.removeItem('lumen_guest_mode');
            window.location.reload();
        } catch (e) {
            console.error("Error resetting guest", e);
            setIsDeleting(false);
        }
        return;
    }

    // Authenticated User: Direct Deletion
    if (window.confirm("Are you sure you want to permanently delete your account? This action cannot be undone and will remove all your data.")) {
        setIsDeleting(true);
        try {
            await deleteUserData(userId);
            // Reload to clear state/auth context
            window.location.reload();
        } catch (e: any) {
            console.error("Error deleting account", e);
            setIsDeleting(false);
            if (e.code === 'auth/requires-recent-login') {
                setMessage({ type: 'error', text: 'Security Check: Please log out and log back in, then try deleting your account again.' });
            } else {
                setMessage({ type: 'error', text: 'Failed to delete account. Please try again later.' });
            }
        }
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative overflow-y-auto">
       <div className="shrink-0 px-6 py-4 bg-white/80 backdrop-blur-md border-b border-brand-100 flex items-center justify-between z-10 sticky top-0">
          <span className="text-brand-800 font-display font-semibold tracking-wide text-lg">Settings</span>
          {!isGuest && (
            <button 
              onClick={onLogout} 
              className="flex items-center space-x-2 px-4 py-2 rounded-lg transition-colors text-sm font-medium bg-red-50 text-red-600 hover:bg-red-100"
              aria-label="Log Out"
            >
                <LogOutIcon className="w-4 h-4" />
                <span>Log Out</span>
            </button>
          )}
       </div>

       <div className="max-w-2xl mx-auto w-full px-6 py-8 pb-20">
          {message && (
            <div role="alert" className={`mb-6 p-4 rounded-xl border text-sm font-medium flex items-center ${message.type === 'success' ? 'bg-green-50 border-green-100 text-green-600' : 'bg-red-50 border-red-100 text-red-600'}`}>
                {message.type === 'success' ? <CheckIcon className="w-5 h-5 mr-2" /> : <XIcon className="w-5 h-5 mr-2" />}
                {message.text}
            </div>
          )}

           <div className="bg-white rounded-2xl p-6 shadow-sm border border-brand-100 space-y-6">
              <div className="flex items-center text-slate-800 font-display font-semibold border-b border-slate-50 pb-2 mb-4">
                <UserIcon className="w-5 h-5 mr-2 text-brand-500" />
                Personal Information
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label htmlFor="firstName" className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1.5">First Name</label>
                  <input id="firstName" type="text" value={profile.firstName} onChange={(e) => setProfile(p => ({...p, firstName: e.target.value}))} className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-brand-400 focus:ring-2 focus:ring-brand-100 outline-none bg-slate-50/50" />
                </div>
                <div>
                  <label htmlFor="lastName" className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1.5">Last Name</label>
                  <input id="lastName" type="text" value={profile.lastName} onChange={(e) => setProfile(p => ({...p, lastName: e.target.value}))} className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-brand-400 focus:ring-2 focus:ring-brand-100 outline-none bg-slate-50/50" />
                </div>
              </div>

              <div>
                 <label htmlFor="email" className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1.5">Email Address</label>
                 <input id="email" type="email" value={profile.email} disabled className="w-full px-4 py-2.5 rounded-xl border border-slate-200 bg-slate-100 text-slate-500 cursor-not-allowed" />
              </div>

              <div>
                <label htmlFor="bio" className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1.5">Bio</label>
                <textarea id="bio" value={profile.bio} onChange={(e) => setProfile(p => ({...p, bio: e.target.value}))} rows={3} className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:border-brand-400 focus:ring-2 focus:ring-brand-100 outline-none bg-slate-50/50 resize-none" placeholder="Tell us a little about yourself..." />
              </div>

              <button 
                  onClick={handleSave}
                  disabled={isSaving || isDeleting}
                  className="w-full py-3.5 rounded-xl font-semibold shadow-md transition-all bg-brand-600 text-white hover:bg-brand-700 disabled:opacity-70 mt-6"
                >
                  {isSaving ? 'Saving...' : 'Save Changes'}
               </button>
           </div>

           {/* Danger Zone */}
           <div className="bg-red-50/50 rounded-2xl p-6 shadow-sm border border-red-100 mt-6">
              <div className="flex items-center text-red-700 font-display font-semibold border-b border-red-100 pb-2 mb-4">
                <ShieldIcon className="w-5 h-5 mr-2" />
                Danger Zone
              </div>
              <p className="text-sm text-red-600/80 mb-4">
                {isGuest 
                    ? "Reset your guest session and clear all locally stored data." 
                    : "Permanently delete your account and all associated data."}
              </p>
              <button 
                onClick={handleDeleteAccount}
                disabled={isDeleting || isSaving}
                className="w-full py-3 rounded-xl font-semibold transition-all bg-white border border-red-200 text-red-600 hover:bg-red-600 hover:text-white hover:border-red-600 disabled:opacity-50 flex items-center justify-center space-x-2"
              >
                 {isDeleting ? (
                    <span>Processing...</span>
                 ) : (
                    <>
                        <TrashIcon className="w-4 h-4" />
                        <span>{isGuest ? "Reset Guest Session" : "Delete My Account"}</span>
                    </>
                 )}
              </button>
           </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { AccessibilityIcon, SunIcon, CheckIcon, XIcon, EyeIcon, PlayIcon, SpeakerIcon } from './Icons';
import { db } from '../services/firebase';
import { doc, setDoc, getDoc } from 'firebase/firestore';

interface AccessibilitySettingsProps {
  userId: string;
}

interface Personality {
  id: string;
  name: string;
  description: string;
  gender: 'male' | 'female';
}

const PERSONALITIES: Personality[] = [
  { id: 'kim', name: 'Kim', description: 'Beautiful & Warm Woman', gender: 'female' },
  { id: 'john', name: 'John', description: 'Strong & Firm Male', gender: 'male' },
  { id: 'stacy', name: 'Stacy', description: 'Professional Woman', gender: 'female' },
];

export const AccessibilitySettings: React.FC<AccessibilitySettingsProps> = ({ userId }) => {
  const [settings, setSettings] = useState({
    textSize: 16,
    highContrast: false,
    reducedMotion: false,
    voiceURI: '',
  });

  const [systemVoices, setSystemVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [message, setMessage] = useState<{type: 'success'|'error', text: string} | null>(null);

  // Load System Voices
  useEffect(() => {
    const loadVoices = () => {
      const available = window.speechSynthesis.getVoices();
      setSystemVoices(available.filter(v => v.lang.includes('en')));
    };
    loadVoices();
    window.speechSynthesis.onvoiceschanged = loadVoices;
    return () => { window.speechSynthesis.onvoiceschanged = null; };
  }, []);

  // Map Personalities to best available System Voices
  const mappedVoices = useMemo(() => {
    if (systemVoices.length === 0) return {};

    const findVoice = (gender: 'male' | 'female', preferredNames: string[]) => {
      // 1. Try to find a "Natural" or "Premium" voice first
      const premium = systemVoices.find(v => 
        (v.name.toLowerCase().includes('natural') || v.name.toLowerCase().includes('premium')) &&
        (gender === 'female' ? !v.name.toLowerCase().includes('male') : v.name.toLowerCase().includes('male'))
      );
      if (premium) return premium;

      // 2. Try preferred names for the personality profile
      for (const name of preferredNames) {
        const found = systemVoices.find(v => v.name.toLowerCase().includes(name.toLowerCase()));
        if (found) return found;
      }

      // 3. Fallback to any voice matching gender
      return systemVoices.find(v => 
        gender === 'female' ? !v.name.toLowerCase().includes('male') : v.name.toLowerCase().includes('male')
      ) || systemVoices[0];
    };

    return {
      kim: findVoice('female', ['samantha', 'google us english', 'victoria']),
      john: findVoice('male', ['daniel', 'google uk english male', 'alex', 'david']),
      stacy: findVoice('female', ['karen', 'google uk english female', 'moira', 'zira']),
    };
  }, [systemVoices]);

  useEffect(() => {
    document.documentElement.style.fontSize = `${settings.textSize}px`;
    if (settings.highContrast) document.body.classList.add('high-contrast');
    else document.body.classList.remove('high-contrast');
    if (settings.reducedMotion) document.body.classList.add('reduced-motion');
    else document.body.classList.remove('reduced-motion');
  }, [settings]);

  useEffect(() => {
    if (!userId) return;
    const fetchSettings = async () => {
      try {
        let data: any = null;
        if (userId === 'guest-dev-user') {
          const saved = localStorage.getItem('lumen_user_profile');
          if (saved) data = JSON.parse(saved);
        } else if (db) {
          const docRef = doc(db, 'users', userId);
          const docSnap = await getDoc(docRef);
          if (docSnap.exists()) data = docSnap.data();
        }
        if (data) {
          setSettings(prev => ({
            textSize: data.textSize || 16,
            highContrast: data.highContrast || false,
            reducedMotion: data.reducedMotion || false,
            voiceURI: data.voiceURI || '',
          }));
        }
      } catch (e) { console.error(e); }
    };
    fetchSettings();
  }, [userId]);

  const handleSave = async () => {
    setIsSaving(true);
    setMessage(null);
    try {
      if (userId === 'guest-dev-user') {
        const local = localStorage.getItem('lumen_user_profile');
        const profile = local ? JSON.parse(local) : {};
        localStorage.setItem('lumen_user_profile', JSON.stringify({ ...profile, ...settings }));
        setMessage({ type: 'success', text: 'Settings updated locally.' });
      } else {
        await setDoc(doc(db, 'users', userId), settings, { merge: true });
        setMessage({ type: 'success', text: 'Accessibility settings saved.' });
      }
    } catch (e) {
      setMessage({ type: 'error', text: 'Failed to save settings.' });
    } finally { setIsSaving(false); }
  };

  const handlePreviewVoice = (uri: string) => {
    window.speechSynthesis.cancel();
    const voice = systemVoices.find(v => v.voiceURI === uri);
    if (voice) {
      const utterance = new SpeechSynthesisUtterance("Hello! I am Lumen, your spiritual companion.");
      utterance.voice = voice;
      window.speechSynthesis.speak(utterance);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative overflow-y-auto">
      <div className="shrink-0 px-6 py-4 bg-white/80 backdrop-blur-md border-b border-brand-100 flex items-center justify-between z-10 sticky top-0">
        <span className="text-brand-800 font-display font-semibold tracking-wide text-lg">Accessibility</span>
      </div>

      <div className="max-w-2xl mx-auto w-full px-6 py-8 pb-20">
        {message && (
          <div role="alert" className={`mb-6 p-4 rounded-xl border text-sm font-medium flex items-center ${message.type === 'success' ? 'bg-green-50 border-green-100 text-green-600' : 'bg-red-50 border-red-100 text-red-600'}`}>
            {message.type === 'success' ? <CheckIcon className="w-5 h-5 mr-2" /> : <XIcon className="w-5 h-5 mr-2" />}
            {message.text}
          </div>
        )}

        <div className="bg-white rounded-2xl p-6 shadow-sm border border-brand-100 space-y-8">
          <div className="flex items-center text-slate-800 font-display font-semibold border-b border-slate-50 pb-2 mb-4">
            <AccessibilityIcon className="w-5 h-5 mr-2 text-brand-500" />
            Display Settings
          </div>

          <div>
            <label htmlFor="textSize" className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Text Size</label>
            <input 
              id="textSize" type="range" min="14" max="24" step="1"
              value={settings.textSize}
              onChange={(e) => setSettings(s => ({...s, textSize: parseInt(e.target.value)}))}
              className="w-full accent-brand-600 h-2 bg-slate-100 rounded-lg appearance-none cursor-pointer"
            />
            <div className="flex justify-between text-xs text-slate-400 mt-2 font-medium">
              <span>Small (14px)</span>
              <span>Default (16px)</span>
              <span>Large (24px)</span>
            </div>
          </div>

          <div className="flex items-center justify-between py-2">
            <div className="flex items-center space-x-3">
              <div className="p-2 bg-slate-100 rounded-lg text-slate-600"><EyeIcon className="w-5 h-5" /></div>
              <div>
                <h4 className="font-semibold text-slate-800">High Contrast Mode</h4>
                <p className="text-xs text-slate-500">Increase contrast for better legibility.</p>
              </div>
            </div>
            <label className="relative inline-flex items-center cursor-pointer">
              <input type="checkbox" className="sr-only peer" checked={settings.highContrast} onChange={(e) => setSettings(s => ({...s, highContrast: e.target.checked}))} />
              <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer-checked:bg-brand-600 after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:after:translate-x-full"></div>
            </label>
          </div>

          <div className="border-t border-slate-100 pt-8">
            <div className="flex items-center text-slate-800 font-display font-semibold border-b border-slate-50 pb-2 mb-4">
              <SpeakerIcon className="w-5 h-5 mr-2 text-brand-500" />
              AI Voice Personality
            </div>

            <div className="space-y-3">
              {PERSONALITIES.map(person => {
                const voice = (mappedVoices as any)[person.id];
                const isActive = settings.voiceURI === voice?.voiceURI;

                return (
                  <button
                    key={person.id}
                    type="button"
                    onClick={() => setSettings(s => ({...s, voiceURI: voice?.voiceURI || ''}))}
                    className={`w-full flex items-center justify-between p-4 rounded-xl border transition-all ${isActive ? 'bg-brand-50 border-brand-300 ring-2 ring-brand-100' : 'bg-white border-slate-100 hover:border-brand-200'}`}
                  >
                    <div className="flex items-center space-x-4">
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center ${isActive ? 'bg-brand-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                        <SpeakerIcon className="w-5 h-5" />
                      </div>
                      <div className="text-left">
                        <h4 className={`font-bold ${isActive ? 'text-brand-800' : 'text-slate-700'}`}>{person.name}</h4>
                        <p className="text-xs text-slate-500">{person.description}</p>
                      </div>
                    </div>
                    {isActive ? (
                      <button 
                        onClick={(e) => { e.stopPropagation(); handlePreviewVoice(voice.voiceURI); }}
                        className="p-2 bg-brand-600 text-white rounded-lg shadow-sm"
                      >
                        <PlayIcon className="w-4 h-4" />
                      </button>
                    ) : (
                      <div className="w-6 h-6 rounded-full border-2 border-slate-200"></div>
                    )}
                  </button>
                );
              })}
            </div>
            <p className="text-xs text-slate-400 mt-4 text-center">These voices are optimized for natural, human-like speech.</p>
          </div>

          <button 
            onClick={handleSave}
            disabled={isSaving}
            className="w-full py-3.5 rounded-xl font-semibold shadow-md transition-all bg-brand-600 text-white hover:bg-brand-700 disabled:opacity-70 mt-6"
          >
            {isSaving ? 'Saving...' : 'Save Settings'}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { AccessibilityIcon, SunIcon, CheckIcon, XIcon, EyeIcon, PlayIcon, SpeakerIcon } from './Icons';
import { db } from '../services/firebase';
import { doc, setDoc, getDoc } from 'firebase/firestore';

interface AccessibilitySettingsProps {
  userId: string;
}

interface Personality {
  id: string;
  name: string;
  description: string;
  gender: 'male' | 'female';
  preferredNames: string[];
}

const PERSONALITIES: Personality[] = [
  { 
    id: 'kim', 
    name: 'Kim', 
    description: 'Beautiful & Warm Woman', 
    gender: 'female',
    preferredNames: ['samantha', 'victoria', 'google us english', 'susan', 'tessa']
  },
  { 
    id: 'john', 
    name: 'John', 
    description: 'Strong & Firm Male', 
    gender: 'male',
    preferredNames: ['daniel', 'alex', 'google uk english male', 'david', 'fred', 'james', 'microsoft david', 'microsoft mark']
  },
  { 
    id: 'stacy', 
    name: 'Stacy', 
    description: 'Professional Woman', 
    gender: 'female',
    preferredNames: ['karen', 'google uk english female', 'moira', 'zira', 'microsoft zira']
  },
];

export const AccessibilitySettings: React.FC<AccessibilitySettingsProps> = ({ userId }) => {
  const [settings, setSettings] = useState({
    textSize: 16,
    highContrast: false,
    reducedMotion: false,
    voiceURI: '',
  });

  const [systemVoices, setSystemVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [message, setMessage] = useState<{type: 'success'|'error', text: string} | null>(null);

  // Load System Voices
  useEffect(() => {
    const loadVoices = () => {
      const available = window.speechSynthesis.getVoices();
      // Filter for English voices only
      setSystemVoices(available.filter(v => v.lang.includes('en')));
    };
    loadVoices();
    // Some browsers need this event to load voices
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
    return () => { window.speechSynthesis.onvoiceschanged = null; };
  }, []);

  // Map Personalities to best available System Voices
  const mappedVoices = useMemo(() => {
    if (systemVoices.length === 0) return {};

    const findVoice = (gender: 'male' | 'female', preferredNames: string[]) => {
      // 1. Try preferred names in order (these are our best bets for the personality)
      for (const pName of preferredNames) {
        const found = systemVoices.find(v => v.name.toLowerCase().includes(pName.toLowerCase()));
        if (found) return found;
      }

      // 2. Try to find a "Premium/Natural/Enhanced" voice of correct gender
      const premium = systemVoices.find(v => {
        const n = v.name.toLowerCase();
        const isPremium = n.includes('natural') || n.includes('premium') || n.includes('enhanced');
        if (!isPremium) return false;

        if (gender === 'male') {
          return n.includes('male') || ['alex', 'daniel', 'fred', 'david', 'james'].some(mn => n.includes(mn));
        } else {
          // For female, avoid names that explicitly say "male"
          return (n.includes('female') || ['samantha', 'victoria', 'karen', 'stacy', 'kim'].some(fn => n.includes(fn))) && !n.includes('male');
        }
      });
      if (premium) return premium;

      // 3. Fallback to any voice that likely matches gender
      const fallback = systemVoices.find(v => {
        const n = v.name.toLowerCase();
        if (gender === 'male') {
          return n.includes('male') || ['alex', 'daniel', 'fred', 'david', 'james', 'oliver'].some(mn => n.includes(mn));
        } else {
          return (n.includes('female') || ['samantha', 'victoria', 'karen', 'moira', 'tessa', 'susan'].some(fn => n.includes(fn))) && !n.includes('male');
        }
      });

      return fallback || systemVoices[0];
    };

    const mapping: Record<string, SpeechSynthesisVoice> = {};
    PERSONALITIES.forEach(p => {
      mapping[p.id] = findVoice(p.gender, p.preferredNames);
    });
    return mapping;
  }, [systemVoices]);

  useEffect(() => {
    document.documentElement.style.fontSize = `${settings.textSize}px`;
    if (settings.highContrast) document.body.classList.add('high-contrast');
    else document.body.classList.remove('high-contrast');
    if (settings.reducedMotion) document.body.classList.add('reduced-motion');
    else document.body.classList.remove('reduced-motion');
  }, [settings]);

  useEffect(() => {
    if (!userId) return;
    const fetchSettings = async () => {
      try {
        let data: any = null;
        if (userId === 'guest-dev-user') {
          const saved = localStorage.getItem('lumen_user_profile');
          if (saved) data = JSON.parse(saved);
        } else if (db) {
          const docRef = doc(db, 'users', userId);
          const docSnap = await getDoc(docRef);
          if (docSnap.exists()) data = docSnap.data();
        }
        if (data) {
          setSettings(prev => ({
            textSize: data.textSize || 16,
            highContrast: data.highContrast || false,
            reducedMotion: data.reducedMotion || false,
            voiceURI: data.voiceURI || '',
          }));
        }
      } catch (e) { console.error(e); }
    };
    fetchSettings();
  }, [userId]);

  const handleSave = async () => {
    setIsSaving(true);
    setMessage(null);
    try {
      if (userId === 'guest-dev-user') {
        const local = localStorage.getItem('lumen_user_profile');
        const profile = local ? JSON.parse(local) : {};
        localStorage.setItem('lumen_user_profile', JSON.stringify({ ...profile, ...settings }));
        setMessage({ type: 'success', text: 'Settings updated locally.' });
      } else {
        await setDoc(doc(db, 'users', userId), settings, { merge: true });
        setMessage({ type: 'success', text: 'Accessibility settings saved.' });
      }
    } catch (e) {
      setMessage({ type: 'error', text: 'Failed to save settings.' });
    } finally { setIsSaving(false); }
  };

  const handlePreviewVoice = (uri: string) => {
    window.speechSynthesis.cancel();
    const voice = systemVoices.find(v => v.voiceURI === uri);
    if (voice) {
      const utterance = new SpeechSynthesisUtterance("Hello! I am Lumen, your spiritual companion.");
      utterance.voice = voice;
      window.speechSynthesis.speak(utterance);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative overflow-y-auto">
      <div className="shrink-0 px-6 py-4 bg-white/80 backdrop-blur-md border-b border-brand-100 flex items-center justify-between z-10 sticky top-0">
        <span className="text-brand-800 font-display font-semibold tracking-wide text-lg">Accessibility</span>
      </div>

      <div className="max-w-2xl mx-auto w-full px-6 py-8 pb-20">
        {message && (
          <div role="alert" className={`mb-6 p-4 rounded-xl border text-sm font-medium flex items-center ${message.type === 'success' ? 'bg-green-50 border-green-100 text-green-600' : 'bg-red-50 border-red-100 text-red-600'}`}>
            {message.type === 'success' ? <CheckIcon className="w-5 h-5 mr-2" /> : <XIcon className="w-5 h-5 mr-2" />}
            {message.text}
          </div>
        )}

        <div className="bg-white rounded-2xl p-6 shadow-sm border border-brand-100 space-y-8">
          <div className="flex items-center text-slate-800 font-display font-semibold border-b border-slate-50 pb-2 mb-4">
            <AccessibilityIcon className="w-5 h-5 mr-2 text-brand-500" />
            Display Settings
          </div>

          <div>
            <label htmlFor="textSize" className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Text Size</label>
            <input 
              id="textSize" type="range" min="14" max="24" step="1"
              value={settings.textSize}
              onChange={(e) => setSettings(s => ({...s, textSize: parseInt(e.target.value)}))}
              className="w-full accent-brand-600 h-2 bg-slate-100 rounded-lg appearance-none cursor-pointer"
            />
            <div className="flex justify-between text-xs text-slate-400 mt-2 font-medium">
              <span>Small (14px)</span>
              <span>Default (16px)</span>
              <span>Large (24px)</span>
            </div>
          </div>

          <div className="flex items-center justify-between py-2">
            <div className="flex items-center space-x-3">
              <div className="p-2 bg-slate-100 rounded-lg text-slate-600"><EyeIcon className="w-5 h-5" /></div>
              <div>
                <h4 className="font-semibold text-slate-800">High Contrast Mode</h4>
                <p className="text-xs text-slate-500">Increase contrast for better legibility.</p>
              </div>
            </div>
            <label className="relative inline-flex items-center cursor-pointer">
              <input type="checkbox" className="sr-only peer" checked={settings.highContrast} onChange={(e) => setSettings(s => ({...s, highContrast: e.target.checked}))} />
              <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer-checked:bg-brand-600 after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:after:translate-x-full"></div>
            </label>
          </div>

          <div className="border-t border-slate-100 pt-8">
            <div className="flex items-center text-slate-800 font-display font-semibold border-b border-slate-50 pb-2 mb-4">
              <SpeakerIcon className="w-5 h-5 mr-2 text-brand-500" />
              AI Voice Personality
            </div>

            <div className="space-y-3">
              {PERSONALITIES.map(person => {
                const voice = (mappedVoices as any)[person.id];
                const isActive = settings.voiceURI === voice?.voiceURI;

                return (
                  <button
                    key={person.id}
                    type="button"
                    onClick={() => setSettings(s => ({...s, voiceURI: voice?.voiceURI || ''}))}
                    className={`w-full flex items-center justify-between p-4 rounded-xl border transition-all ${isActive ? 'bg-brand-50 border-brand-300 ring-2 ring-brand-100' : 'bg-white border-slate-100 hover:border-brand-200'}`}
                  >
                    <div className="flex items-center space-x-4">
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center ${isActive ? 'bg-brand-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                        {person.gender === 'male' ? (
                          <span className="font-bold text-lg">M</span>
                        ) : (
                          <span className="font-bold text-lg">F</span>
                        )}
                      </div>
                      <div className="text-left">
                        <h4 className={`font-bold ${isActive ? 'text-brand-800' : 'text-slate-700'}`}>{person.name}</h4>
                        <p className="text-xs text-slate-500">{person.description}</p>
                      </div>
                    </div>
                    {isActive ? (
                      <button 
                        onClick={(e) => { e.stopPropagation(); handlePreviewVoice(voice.voiceURI); }}
                        className="p-2 bg-brand-600 text-white rounded-lg shadow-sm"
                      >
                        <PlayIcon className="w-4 h-4" />
                      </button>
                    ) : (
                      <div className="w-6 h-6 rounded-full border-2 border-slate-200"></div>
                    )}
                  </button>
                );
              })}
            </div>
            <p className="text-xs text-slate-400 mt-4 text-center">These voices are chosen from your system to sound natural and non-robotic.</p>
          </div>

          <button 
            onClick={handleSave}
            disabled={isSaving}
            className="w-full py-3.5 rounded-xl font-semibold shadow-md transition-all bg-brand-600 text-white hover:bg-brand-700 disabled:opacity-70 mt-6"
          >
            {isSaving ? 'Saving...' : 'Save Settings'}
          </button>
        </div>
      </div>
    </div>
  );
};

import React from 'react';

export enum Role {
  USER = 'user',
  MODEL = 'model'
}

export interface Message {
  id: string;
  role: Role;
  text: string;
  isStreaming?: boolean;
  timestamp: number;
}

export interface ChatSession {
  id: string;
  title: string;
  lastMessage: string;
  timestamp: number;
  messages: Message[];
}

export interface DailyVerse {
  text: string;
  reference: string;
}

export interface Topic {
  id: string;
  label: string;
  icon: React.ReactNode;
  prompt: string;
}

export interface PrayerRequest {
  id: string;
  title: string;
  content: string;
  description?: string;
  date: number;
  isAnswered: boolean;
  reminderTime?: number;
}

export interface ActivityLog {
  id: string;
  taskId: string;
  taskTitle: string;
  content: string;
  timestamp: number;
}

export interface FavoriteVerse {
  id: string;
  reference: string;
  text: string;
  date: number;
  source?: 'daily' | 'chat';
}

export interface UserProfile {
  firstName: string;
  lastName: string;
  email: string;
  dateOfBirth: string;
  jobTitle: string;
  onlineStatus: 'Online' | 'Offline';
  bio: string;
  photo?: string; // base64 data url
  passwordHistory?: string[];
  // Accessibility Settings
  textSize?: number;
  highContrast?: boolean;
  reducedMotion?: boolean;
  voiceURI?: string;
}

export type ViewState = 'journey' | 'chat' | 'prayer' | 'illustrator' | 'settings' | 'favorites' | 'about' | 'zodiac' | 'accessibility';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GenerateContentResponse, Content } from "@google/genai";
import { getChatSession, resetChatSession } from '../services/geminiService';
import { Message, Role, ChatSession as ChatSessionType } from '../types';
import { SendIcon, RefreshIcon, DoveIcon, BookIcon, HeartIcon, ShareIcon, CheckIcon, SpeakerIcon, StopIcon, CopyIcon, PlusIcon } from './Icons';
import { DailyVerseCard } from './DailyVerseCard';
import { db } from '../services/firebase';
import { collection, doc, setDoc, getDoc, addDoc, updateDoc } from 'firebase/firestore';
import { ShareModal } from './ShareModal';

interface ChatProps {
  userId: string;
  chatId: string | null;
  onChatCreated: (id: string) => void;
  initialPrompt?: string;
  onClearInitialPrompt?: () => void;
}

const findBibleReference = (text: string): string | null => {
  const regex = /\b((?:1|2|3|I|II|III)\s?)?[A-Z][a-z]+\.?\s\d+(?::\d+(?:-\d+)?)?\b/;
  const match = text.match(regex);
  return match ? match[0] : null;
};

export const Chat: React.FC<ChatProps> = ({ userId, chatId, onChatCreated, initialPrompt, onClearInitialPrompt }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const [sharingMessage, setSharingMessage] = useState<{text: string, id: string} | null>(null);
  const [preferredVoice, setPreferredVoice] = useState<string>('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const hasLoadedHistory = useRef(false);

  // Load User Preferences (Voice)
  useEffect(() => {
    const fetchPreferences = async () => {
        if (!userId) return;

        let voice = '';
        if (userId === 'guest-dev-user') {
            const saved = localStorage.getItem('lumen_user_profile');
            if (saved) {
                try {
                    const parsed = JSON.parse(saved);
                    voice = parsed.voiceURI || '';
                } catch (e) {}
            }
        } else if (db) {
            try {
                const docRef = doc(db, 'users', userId);
                const docSnap = await getDoc(docRef);
                if (docSnap.exists()) {
                    voice = docSnap.data().voiceURI || '';
                }
            } catch (e) {}
        }
        setPreferredVoice(voice);
    };
    fetchPreferences();
  }, [userId]);

  // Load specific chat history
  useEffect(() => {
    const loadHistory = async () => {
      hasLoadedHistory.current = false;
      if (!chatId) {
        const welcomeMsg: Message = { id: 'welcome', role: Role.MODEL, text: "Welcome. I am Lumen. How can I support your spiritual journey today?", timestamp: Date.now() };
        setMessages([welcomeMsg]);
        resetChatSession([]);
        hasLoadedHistory.current = true;
        return;
      }

      try {
        if (userId === 'guest-dev-user') {
          const saved = localStorage.getItem('lumen_chats');
          if (saved) {
             const allChats = JSON.parse(saved) as ChatSessionType[];
             const currentChat = allChats.find(c => c.id === chatId);
             if (currentChat) {
               setMessages(currentChat.messages);
               const history: Content[] = currentChat.messages
                 .filter((m: Message) => m.id !== 'welcome' && !m.isStreaming)
                 .map((m: Message) => ({
                   role: m.role,
                   parts: [{ text: m.text }]
                 }));
               resetChatSession(history);
             }
          }
        } else if (db) {
            const docRef = doc(db, 'users', userId, 'chats', chatId);
            const docSnap = await getDoc(docRef);
            if (docSnap.exists()) {
              const savedMessages = docSnap.data().messages as Message[];
              setMessages(savedMessages);

              const history: Content[] = savedMessages
                .filter(m => m.id !== 'welcome' && !m.isStreaming)
                .map(m => ({
                  role: m.role,
                  parts: [{ text: m.text }]
                }));
              resetChatSession(history);
            }
        }
      } catch (e) {
        console.error("Error loading chat history", e);
      } finally {
        hasLoadedHistory.current = true;
      }
    };

    if (userId) loadHistory();
  }, [userId, chatId]);

  // Save specific chat history
  useEffect(() => {
    if (!hasLoadedHistory.current || messages.length === 0 || !chatId) return;
    const saveHistory = async () => {
        try {
            const title = messages.find(m => m.role === Role.USER)?.text.substring(0, 40) || 'New Conversation';
            const lastMessage = messages[messages.length - 1].text;

            if (userId === 'guest-dev-user') {
                const saved = localStorage.getItem('lumen_chats');
                let allChats = saved ? JSON.parse(saved) as ChatSessionType[] : [];
                const chatIndex = allChats.findIndex(c => c.id === chatId);

                if (chatIndex >= 0) {
                    allChats[chatIndex] = { ...allChats[chatIndex], messages, lastMessage, timestamp: Date.now() };
                } else {
                    allChats.push({ id: chatId, title, lastMessage, timestamp: Date.now(), messages });
                }
                localStorage.setItem('lumen_chats', JSON.stringify(allChats));
            } else if (db) {
                await setDoc(doc(db, 'users', userId, 'chats', chatId), { 
                  messages, 
                  title, 
                  lastMessage, 
                  timestamp: Date.now() 
                }, { merge: true });
            }
        } catch (e) { console.error("Error saving chat", e); }
    };
    const timeout = setTimeout(saveHistory, 1000);
    return () => clearTimeout(timeout);
  }, [messages, userId, chatId]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = useCallback(async (text: string) => {
    if (!text.trim() || isLoading) return;

    window.speechSynthesis.cancel();
    setSpeakingId(null);

    let currentChatId = chatId;

    // If it's a new chat, generate an ID and notify parent
    if (!currentChatId) {
      currentChatId = Date.now().toString();
      onChatCreated(currentChatId);
    }

    const userMsg: Message = {
      id: Date.now().toString(),
      role: Role.USER,
      text: text,
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const chat = getChatSession();
      const botMsgId = (Date.now() + 1).toString();
      setMessages(prev => [
        ...prev,
        {
          id: botMsgId,
          role: Role.MODEL,
          text: '',
          isStreaming: true,
          timestamp: Date.now(),
        }
      ]);

      const result = await chat.sendMessageStream({ message: text });
      let fullText = '';

      for await (const chunk of result) {
        const chunkText = (chunk as GenerateContentResponse).text || '';
        fullText += chunkText;
        setMessages(prev => prev.map(msg => msg.id === botMsgId ? { ...msg, text: fullText } : msg));
      }

      setMessages(prev => prev.map(msg => msg.id === botMsgId ? { ...msg, isStreaming: false } : msg));

    } catch (error) {
      console.error("Error sending message:", error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: Role.MODEL, text: "I apologize, but I am having trouble connecting right now.", timestamp: Date.now() }]);
    } finally {
      setIsLoading(false);
    }
  }, [isLoading, chatId, onChatCreated]);

  useEffect(() => {
    if (initialPrompt && hasLoadedHistory.current) {
      handleSend(initialPrompt);
      if(onClearInitialPrompt) onClearInitialPrompt();
    }
  }, [initialPrompt, hasLoadedHistory.current]);

  const handleReset = () => {
    onChatCreated(''); // Trigger a new chat by clearing ID in parent
  };

  const handleRegenerate = async () => {
    if (isLoading || messages.length < 2) return;
    const lastMsg = messages[messages.length - 1];
    if (lastMsg.role !== Role.MODEL) return;
    const userMsg = messages[messages.length - 2];
    if (!userMsg || userMsg.role !== Role.USER) return;

    window.speechSynthesis.cancel();
    setSpeakingId(null);

    const keptMessages = messages.slice(0, -2);
    setMessages(keptMessages);

    const history = keptMessages
      .filter(m => m.id !== 'welcome' && !m.isStreaming)
      .map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

    resetChatSession(history);
    await handleSend(userMsg.text);
  };

  const handleSaveVerse = async (text: string, reference: string) => {
      const newFav = { reference, text, date: Date.now(), source: 'chat' as const };
      try {
        if (userId === 'guest-dev-user') {
            const local = localStorage.getItem('lumen_favorites');
            const favs = local ? JSON.parse(local) : [];
            favs.unshift({ ...newFav, id: Date.now().toString() });
            localStorage.setItem('lumen_favorites', JSON.stringify(favs));
        } else if (db) {
            await addDoc(collection(db, 'users', userId, 'favorites'), newFav);
        }
        alert("Verse saved to favorites!");
      } catch (e) { console.error("Error saving favorite", e); }
  };

  const handleCopy = async (text: string, id: string) => {
    try {
      await navigator.clipboard.writeText(text);
      setCopiedId(id);
      setTimeout(() => setCopiedId(null), 2000);
    } catch (err) { console.error('Failed to copy text', err); }
  };

  const handleSpeak = (text: string, id: string) => {
      if (speakingId === id) {
          window.speechSynthesis.cancel();
          setSpeakingId(null);
      } else {
          window.speechSynthesis.cancel();
          const utterance = new SpeechSynthesisUtterance(text);
          if (preferredVoice) {
              const voices = window.speechSynthesis.getVoices();
              const voice = voices.find(v => v.voiceURI === preferredVoice);
              if (voice) utterance.voice = voice;
          }
          utterance.onend = () => setSpeakingId(null);
          utterance.onerror = () => setSpeakingId(null);
          window.speechSynthesis.speak(utterance);
          setSpeakingId(id);
      }
  };

  return (
    <div className="flex flex-col h-full relative">
      <div className="shrink-0 px-6 py-4 bg-white/80 backdrop-blur-md border-b border-brand-100 flex justify-between items-center z-10">
        <div className="flex items-center space-x-3">
          <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse" aria-hidden="true"></div>
          <span className="text-brand-800 font-display font-semibold tracking-wide">
            {chatId ? "Continuing Study" : "New Study Session"}
          </span>
        </div>
        <button 
            onClick={handleReset} 
            className="flex items-center space-x-2 px-4 py-2 bg-brand-50 text-brand-700 rounded-xl hover:bg-brand-100 transition-colors text-sm font-bold uppercase tracking-wider"
            aria-label="New Chat"
        >
          <PlusIcon className="w-4 h-4" />
          <span>New Chat</span>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 sm:p-6 pb-32" aria-live="polite">
        <div className="max-w-3xl mx-auto space-y-6">
          {!chatId && <DailyVerseCard userId={userId} />}
          {messages.map((msg, index) => {
            const reference = msg.role === Role.MODEL && !msg.isStreaming ? findBibleReference(msg.text) : null;
            const isLastMessage = index === messages.length - 1;

            return (
            <div key={msg.id} className={`flex w-full ${msg.role === Role.USER ? 'justify-end' : 'justify-start items-end'}`}>
              {msg.role === Role.MODEL && (
                <div className="flex-shrink-0 mr-2.5 mb-1" aria-hidden="true">
                  <div className="w-8 h-8 rounded-full bg-gradient-to-br from-brand-100 to-white border border-brand-200 flex items-center justify-center shadow-sm text-brand-500">
                    <DoveIcon className="w-4 h-4" />
                  </div>
                </div>
              )}
              <div className={`max-w-[90%] sm:max-w-[80%] rounded-2xl px-5 py-4 shadow-sm leading-relaxed ${msg.role === Role.USER ? 'bg-brand-600 text-white rounded-br-none' : 'bg-gradient-to-br from-white to-brand-50 text-slate-700 rounded-bl-none border border-brand-100 group relative'}`}>
                <div className="whitespace-pre-wrap font-sans text-[15px] sm:text-[16px]">
                  {msg.text}
                  {msg.isStreaming && msg.text.length > 0 && <span className="inline-block w-1.5 h-4 ml-0.5 align-middle bg-brand-400/80 animate-pulse rounded-[1px]"></span>}
                  {msg.isStreaming && msg.text.length === 0 && (
                    <div className="flex space-x-1 items-center h-6 my-1">
                      <div className="w-1.5 h-1.5 bg-brand-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                      <div className="w-1.5 h-1.5 bg-brand-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                      <div className="w-1.5 h-1.5 bg-brand-400 rounded-full animate-bounce"></div>
                    </div>
                  )}
                </div>
                {msg.role === Role.MODEL && !msg.isStreaming && (
                  <div className="mt-3 pt-3 border-t border-brand-100/50 flex flex-wrap gap-2 items-center justify-between">
                    <div>
                      {reference && (
                        <button onClick={() => handleSend(`Read surrounding verses for ${reference}`)} className="flex items-center space-x-1.5 px-3 py-1.5 bg-white/60 hover:bg-white rounded-lg text-xs font-medium text-brand-700 transition-colors border border-brand-100 shadow-sm">
                          <BookIcon className="w-3.5 h-3.5 text-brand-400" />
                          <span>Read Context</span>
                        </button>
                      )}
                    </div>
                    <div className="flex items-center space-x-2">
                       {isLastMessage && (
                           <button onClick={handleRegenerate} className="flex items-center space-x-1 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-brand-600 transition-colors hover:bg-white/60">
                              <RefreshIcon className="w-4 h-4" />
                              <span className="hidden sm:inline">Regenerate</span>
                           </button>
                       )}
                       <button onClick={() => handleSpeak(msg.text, msg.id)} className="flex items-center space-x-1 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-brand-600 transition-colors hover:bg-white/60">
                          {speakingId === msg.id ? <StopIcon className="w-4 h-4 text-brand-600 animate-pulse" /> : <SpeakerIcon className="w-4 h-4" />}
                          <span className="hidden sm:inline">{speakingId === msg.id ? 'Stop' : 'Listen'}</span>
                       </button>
                       {reference && (
                        <button onClick={() => handleSaveVerse(msg.text, reference)} className="flex items-center space-x-1 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-red-500 transition-colors hover:bg-white/60">
                            <HeartIcon className="w-4 h-4" />
                            <span className="hidden sm:inline">Save</span>
                        </button>
                       )}
                       <button onClick={() => handleCopy(msg.text, msg.id)} className="flex items-center space-x-1 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-brand-600 transition-colors hover:bg-white/60">
                          {copiedId === msg.id ? <CheckIcon className="w-4 h-4 text-green-500" /> : <CopyIcon className="w-4 h-4" />}
                          <span className="hidden sm:inline">{copiedId === msg.id ? 'Copied' : 'Copy'}</span>
                       </button>
                       <button onClick={() => setSharingMessage({ text: msg.text, id: msg.id })} className="flex items-center space-x-1 px-3 py-1.5 rounded-lg text-xs font-medium text-slate-400 hover:text-brand-600 transition-colors hover:bg-white/60">
                          <ShareIcon className="w-4 h-4" />
                          <span className="hidden sm:inline">Share</span>
                       </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          )})}
          <div ref={messagesEndRef} />
        </div>
      </div>

      <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-slate-50 via-slate-50 to-transparent">
        <div className="max-w-3xl mx-auto bg-white rounded-2xl shadow-xl border border-brand-100 p-2 flex items-end space-x-2 ring-1 ring-brand-100/50">
          <textarea
            id="chatInput"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(input); }}}
            placeholder="Ask a question..."
            className="flex-1 max-h-32 min-h-[52px] bg-transparent border-none focus:ring-0 text-slate-800 placeholder-slate-400 resize-none p-3"
            rows={1}
          />
          <button 
            onClick={() => handleSend(input)} 
            disabled={!input.trim() || isLoading} 
            className={`p-3 rounded-xl flex-shrink-0 transition-all duration-200 ${input.trim() && !isLoading ? 'bg-brand-600 text-white shadow-md hover:bg-brand-700' : 'bg-slate-100 text-slate-400 cursor-not-allowed'}`}
          >
            <SendIcon className="w-5 h-5" />
          </button>
        </div>
      </div>

      <ShareModal isOpen={!!sharingMessage} onClose={() => setSharingMessage(null)} text={sharingMessage?.text || ''} />
    </div>
  );
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Chat } from './components/Chat';
import { PrayerWall } from './components/PrayerWall';
import { Journey } from './components/Journey';
import { ProfileSettings } from './components/ProfileSettings';
import { Favorites } from './components/Favorites';
import { About } from './components/About';
import { ZodiacDaily } from './components/ZodiacDaily';
import { AccessibilitySettings } from './components/AccessibilitySettings';
import { LoginScreen } from './components/LoginScreen';
import { BibleIllustrator } from './components/BibleIllustrator';
import { ReminderListener } from './components/ReminderListener';
import { 
  MenuIcon, BookIcon, MessageCircleIcon, HandsIcon, MapIcon, SettingsIcon, DoveIcon, BookmarkIcon,
  SparklesIcon, HeartIcon, FeatherIcon, SunIcon, AnchorIcon, ShieldIcon, UsersIcon, BriefcaseIcon, LeafIcon, FireIcon,
  MoonIcon, CloudIcon, LightbulbIcon, SmileIcon, TrendingUpIcon, ArrowDownIcon, InfoIcon, StarIcon, AccessibilityIcon, ImageIcon, PlusIcon, ClockIcon, TrashIcon
} from './components/Icons';
import { ViewState, Topic, ChatSession } from './types';
import { auth, isFirebaseConfigValid, db } from './services/firebase';
import { onAuthStateChanged, User, signOut } from 'firebase/auth';
import { doc, getDoc, collection, onSnapshot, query, orderBy, deleteDoc } from 'firebase/firestore';

const TOPICS: Topic[] = [
  { id: 'anxiety', label: 'Anxiety & Fear', icon: <DoveIcon className="w-5 h-5" />, prompt: "I am feeling anxious. Can you share some bible verses to help me find peace?" },
  { id: 'faith', label: 'Growing Faith', icon: <BookIcon className="w-5 h-5" />, prompt: "How can I strengthen my faith in difficult times?" },
  { id: 'guidance', label: 'Seeking Guidance', icon: <MapIcon className="w-5 h-5" />, prompt: "I need guidance for a big decision. What does the Bible say about wisdom?" },
  { id: 'relationships', label: 'Relationships', icon: <HandsIcon className="w-5 h-5" />, prompt: "How can I build Godly relationships and handle conflict?" },
  { id: 'purpose', label: 'Finding Purpose', icon: <SparklesIcon className="w-5 h-5" />, prompt: "What does the Bible say about finding my purpose in life?" },
  { id: 'healing', label: 'Healing & Comfort', icon: <HeartIcon className="w-5 h-5" />, prompt: "I need comfort and healing. Please share some scriptures for physical and emotional restoration." },
];

const MOCK_USER = {
  uid: 'guest-dev-user',
  email: 'guest@lumen.app',
  displayName: 'Guest User',
  isAnonymous: true,
  providerId: 'guest',
} as User;

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [guestUser, setGuestUser] = useState<User | null>(MOCK_USER);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [currentView, setCurrentView] = useState<ViewState>('journey');
  const [startPrompt, setStartPrompt] = useState<string | undefined>(undefined);
  const [showAuthModal, setShowAuthModal] = useState(false);

  // History State
  const [activeChatId, setActiveChatId] = useState<string | null>(null);
  const [recentChats, setRecentChats] = useState<ChatSession[]>([]);

  const isDemoMode = !isFirebaseConfigValid();
  const activeUser = user || guestUser;
  const effectiveUser = activeUser || MOCK_USER;

  // Listen for Auth
  useEffect(() => {
    if (isDemoMode || !auth) {
      setIsAuthLoading(false);
      return;
    }
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        setGuestUser(null);
        localStorage.setItem('lumen_guest_mode', 'false');
        setShowAuthModal(false);
      }
      setIsAuthLoading(false);
    });
    return () => unsubscribe();
  }, [isDemoMode]);

  // Global Settings Application
  useEffect(() => {
    const applySettings = async () => {
      if (!effectiveUser.uid) return;
      let settings: any = {};
      if (effectiveUser.uid === 'guest-dev-user') {
        const saved = localStorage.getItem('lumen_user_profile');
        if (saved) settings = JSON.parse(saved);
      } else if (db) {
        try {
          const docRef = doc(db, 'users', effectiveUser.uid);
          const docSnap = await getDoc(docRef);
          if (docSnap.exists()) settings = docSnap.data();
        } catch (e) {}
      }
      if (settings.textSize) document.documentElement.style.fontSize = `${settings.textSize}px`;
      if (settings.highContrast) document.body.classList.add('high-contrast');
      else document.body.classList.remove('high-contrast');
      if (settings.reducedMotion) document.body.classList.add('reduced-motion');
      else document.body.classList.remove('reduced-motion');
    };
    applySettings();
  }, [effectiveUser.uid]);

  // Load Recent Chats
  useEffect(() => {
    if (!effectiveUser.uid) return;
    if (effectiveUser.uid === 'guest-dev-user') {
      const saved = localStorage.getItem('lumen_chats');
      if (saved) {
        setRecentChats(JSON.parse(saved));
      }
      return;
    }
    if (db) {
      const q = query(collection(db, 'users', effectiveUser.uid, 'chats'), orderBy('timestamp', 'desc'));
      const unsubscribe = onSnapshot(q, (snapshot) => {
        setRecentChats(snapshot.docs.map(d => ({ id: d.id, ...d.data() } as ChatSession)));
      });
      return () => unsubscribe();
    }
  }, [effectiveUser.uid]);

  const handleLogout = useCallback(async () => {
    try {
      if (guestUser) { setShowAuthModal(true); return; }
      if (user && auth) await signOut(auth);
      setGuestUser(MOCK_USER);
      localStorage.setItem('lumen_guest_mode', 'true');
      setCurrentView('journey');
      document.documentElement.style.fontSize = '';
      document.body.classList.remove('high-contrast', 'reduced-motion');
    } catch (error) {}
  }, [user, guestUser]);

  const handleTopicClick = (prompt: string) => {
    setStartPrompt(prompt);
    setActiveChatId(null); // Start fresh
    setCurrentView('chat');
    if (window.innerWidth < 768) setIsSidebarOpen(false);
  };

  const selectChat = (id: string) => {
    setActiveChatId(id);
    setCurrentView('chat');
    if (window.innerWidth < 768) setIsSidebarOpen(false);
  };

  const deleteChat = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!window.confirm("Delete this conversation?")) return;
    try {
      if (effectiveUser.uid === 'guest-dev-user') {
        const filtered = recentChats.filter(c => c.id !== id);
        setRecentChats(filtered);
        localStorage.setItem('lumen_chats', JSON.stringify(filtered));
      } else if (db) {
        await deleteDoc(doc(db, 'users', effectiveUser.uid, 'chats', id));
      }
      if (activeChatId === id) setActiveChatId(null);
    } catch (err) {}
  };

  if (isAuthLoading) {
    return (
      <div className="h-screen flex items-center justify-center bg-brand-50">
        <div className="animate-pulse flex flex-col items-center">
          <div className="w-12 h-12 bg-brand-200 rounded-full mb-4"></div>
          <div className="h-4 w-32 bg-brand-200 rounded"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-brand-50 text-slate-800 overflow-hidden font-sans relative">
      {effectiveUser && <ReminderListener userId={effectiveUser.uid} />}
      {showAuthModal && <LoginScreen onLoginSuccess={() => setShowAuthModal(false)} onGuestLogin={() => setShowAuthModal(false)} onClose={() => setShowAuthModal(false)} isDemoMode={isDemoMode} />}
      {isSidebarOpen && <div className="fixed inset-0 bg-black/20 backdrop-blur-sm z-40 md:hidden" onClick={() => setIsSidebarOpen(false)}></div>}

      <aside className={`fixed md:static inset-y-0 left-0 z-50 w-72 bg-white border-r border-brand-100 transform transition-transform duration-300 ease-in-out flex flex-col ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <div className="p-6 flex items-center justify-center border-b border-brand-50/50">
          <div className="w-10 h-10 bg-brand-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-brand-500/30 mr-3">
            <DoveIcon className="w-6 h-6" />
          </div>
          <div>
            <h1 className="font-display text-xl font-semibold text-slate-800 leading-none">Bible Chat</h1>
            <span className="text-[10px] font-medium text-brand-400 uppercase tracking-widest">Holy Bible Study</span>
          </div>
        </div>

        <nav className="flex-1 overflow-y-auto p-4 space-y-6">
          <div className="space-y-1">
            <p className="px-4 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Main</p>
            <button onClick={() => { setCurrentView('journey'); setIsSidebarOpen(false); }} className={`w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl transition-colors ${currentView === 'journey' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}><MapIcon className="w-5 h-5" /><span className="font-medium">Journey</span></button>
            <button onClick={() => { setCurrentView('chat'); setActiveChatId(null); setIsSidebarOpen(false); }} className={`w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl transition-colors ${currentView === 'chat' && !activeChatId ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}><PlusIcon className="w-5 h-5" /><span className="font-medium">New Study</span></button>
            <button onClick={() => { setCurrentView('illustrator'); setIsSidebarOpen(false); }} className={`w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl transition-colors ${currentView === 'illustrator' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}><ImageIcon className="w-5 h-5" /><span className="font-medium">Illustrator</span></button>
            <button onClick={() => { setCurrentView('prayer'); setIsSidebarOpen(false); }} className={`w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl transition-colors ${currentView === 'prayer' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}><HandsIcon className="w-5 h-5" /><span className="font-medium">Prayer Wall</span></button>
            <button onClick={() => { setCurrentView('favorites'); setIsSidebarOpen(false); }} className={`w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl transition-colors ${currentView === 'favorites' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}><BookmarkIcon className="w-5 h-5" /><span className="font-medium">Favorites</span></button>
          </div>

          {recentChats.length > 0 && (
            <div className="space-y-1">
              <p className="px-4 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Recent Chats</p>
              <div className="max-h-64 overflow-y-auto space-y-1 scrollbar-hide">
                {recentChats.map(chat => (
                  <button key={chat.id} onClick={() => selectChat(chat.id)} className={`w-full group flex items-center justify-between px-4 py-2.5 rounded-xl transition-all ${activeChatId === chat.id ? 'bg-brand-100 text-brand-800' : 'text-slate-600 hover:bg-slate-50'}`}>
                    <div className="flex items-center space-x-3 overflow-hidden">
                      <MessageCircleIcon className="w-4 h-4 shrink-0 text-brand-300" />
                      <div className="flex flex-col text-left overflow-hidden">
                        <span className="text-sm font-medium truncate">{chat.title || 'Conversation'}</span>
                        <span className="text-[10px] text-slate-400 flex items-center"><ClockIcon className="w-2.5 h-2.5 mr-1" />{new Date(chat.timestamp).toLocaleDateString()}</span>
                      </div>
                    </div>
                    <button onClick={(e) => deleteChat(e, chat.id)} className="opacity-0 group-hover:opacity-100 p-1 text-slate-400 hover:text-red-500 rounded-md transition-opacity"><TrashIcon className="w-3.5 h-3.5" /></button>
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="space-y-1">
            <p className="px-4 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Topics</p>
            {TOPICS.slice(0, 4).map((topic) => (
              <button key={topic.id} onClick={() => handleTopicClick(topic.prompt)} className="w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl text-slate-600 hover:bg-brand-50 hover:text-brand-700 transition-all group">
                <div className="text-slate-400 group-hover:text-brand-500 transition-colors">{topic.icon}</div>
                <span className="font-medium text-sm">{topic.label}</span>
              </button>
            ))}
          </div>
        </nav>

        <div className="p-4 border-t border-slate-100 space-y-1">
           <button onClick={() => { setCurrentView('accessibility'); setIsSidebarOpen(false); }} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-colors ${currentView === 'accessibility' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}><AccessibilityIcon className="w-5 h-5" /><span className="font-medium">Accessibility</span></button>
           <button onClick={() => { setCurrentView('settings'); setIsSidebarOpen(false); }} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-colors ${currentView === 'settings' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}><SettingsIcon className="w-5 h-5" /><span className="font-medium">Settings</span></button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full relative w-full">
        <header className="md:hidden flex items-center justify-between p-4 bg-white border-b border-brand-100">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 text-slate-600 rounded-lg hover:bg-slate-50"><MenuIcon className="w-6 h-6" /></button>
          <span className="font-display font-semibold text-lg text-slate-800">Bible Chat</span>
          <div className="w-10"></div>
        </header>

        <div className="flex-1 overflow-hidden relative bg-slate-50">
          <div className="relative z-10 h-full flex flex-col max-w-5xl mx-auto w-full">
             <div className="flex-1 h-full overflow-hidden">
               {currentView === 'journey' && <Journey userId={effectiveUser.uid} onNavigateToChat={handleTopicClick} />}
               {currentView === 'chat' && <Chat userId={effectiveUser.uid} chatId={activeChatId} onChatCreated={setActiveChatId} initialPrompt={startPrompt} onClearInitialPrompt={() => setStartPrompt(undefined)} />}
               {currentView === 'illustrator' && <BibleIllustrator />}
               {currentView === 'prayer' && <PrayerWall userId={effectiveUser.uid} onPrayWithAI={handleTopicClick} />}
               {currentView === 'favorites' && <Favorites userId={effectiveUser.uid} />}
               {currentView === 'zodiac' && <ZodiacDaily userId={effectiveUser.uid} />}
               {currentView === 'about' && <About />}
               {currentView === 'accessibility' && <AccessibilitySettings userId={effectiveUser.uid} />}
               {currentView === 'settings' && <ProfileSettings userId={effectiveUser.uid} userEmail={effectiveUser.email} onLogout={handleLogout} />}
             </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

