  { id: 'guidance', label: 'Seeking Guidance', icon: <MapIcon className="w-5 h-5" />, prompt: "I need guidance for a big decision. What does the Bible say about wisdom?" },
  { id: 'relationships', label: 'Relationships', icon: <HandsIcon className="w-5 h-5" />, prompt: "How can I build Godly relationships and handle conflict?" },
  { id: 'purpose', label: 'Finding Purpose', icon: <SparklesIcon className="w-5 h-5" />, prompt: "What does the Bible say about finding my purpose in life?" },
  { id: 'healing', label: 'Healing & Comfort', icon: <HeartIcon className="w-5 h-5" />, prompt: "I need comfort and healing. Please share some scriptures for physical and emotional restoration." },
];

const MOCK_USER = {
  uid: 'guest-dev-user',
  email: 'guest@lumen.app',
  displayName: 'Guest User',
  isAnonymous: true,
  providerId: 'guest',
} as User;

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [guestUser, setGuestUser] = useState<User | null>(MOCK_USER);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [currentView, setCurrentView] = useState<ViewState>('journey');
  const [startPrompt, setStartPrompt] = useState<string | undefined>(undefined);
  const [showAuthModal, setShowAuthModal] = useState(false);

  // History State
  const [activeChatId, setActiveChatId] = useState<string | null>(null);
  const [recentChats, setRecentChats] = useState<ChatSession[]>([]);

  const isDemoMode = !isFirebaseConfigValid();
  const activeUser = user || guestUser;
  const effectiveUser = activeUser || MOCK_USER;

  // Listen for Auth
  useEffect(() => {
    if (isDemoMode || !auth) {
      setIsAuthLoading(false);
      return;
    }
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        setGuestUser(null);
        localStorage.setItem('lumen_guest_mode', 'false');
        setShowAuthModal(false);
      }
      setIsAuthLoading(false);
    });
    return () => unsubscribe();
  }, [isDemoMode]);

  // Global Settings Application
  useEffect(() => {
    const applySettings = async () => {
      if (!effectiveUser.uid) return;
      let settings: any = {};
      if (effectiveUser.uid === 'guest-dev-user') {
        const saved = localStorage.getItem('lumen_user_profile');
        if (saved) settings = JSON.parse(saved);
      } else if (db) {
        try {
          const docRef = doc(db, 'users', effectiveUser.uid);
          const docSnap = await getDoc(docRef);
          if (docSnap.exists()) settings = docSnap.data();
        } catch (e) {}
      }
      if (settings.textSize) document.documentElement.style.fontSize = `${settings.textSize}px`;
      if (settings.highContrast) document.body.classList.add('high-contrast');
      else document.body.classList.remove('high-contrast');
      if (settings.reducedMotion) document.body.classList.add('reduced-motion');
      else document.body.classList.remove('reduced-motion');
    };
    applySettings();
  }, [effectiveUser.uid]);

  // Load Recent Chats
  useEffect(() => {
    if (!effectiveUser.uid) return;
    if (effectiveUser.uid === 'guest-dev-user') {
      const saved = localStorage.getItem('lumen_chats');
      if (saved) {
        setRecentChats(JSON.parse(saved));
      }
      return;
    }
    if (db) {
      const q = query(collection(db, 'users', effectiveUser.uid, 'chats'), orderBy('timestamp', 'desc'));
      const unsubscribe = onSnapshot(q, (snapshot) => {
        setRecentChats(snapshot.docs.map(d => ({ id: d.id, ...d.data() } as ChatSession)));
      });
      return () => unsubscribe();
    }
  }, [effectiveUser.uid]);

  const handleLogout = useCallback(async () => {
    try {
      if (guestUser) { setShowAuthModal(true); return; }
      if (user && auth) await signOut(auth);
      setGuestUser(MOCK_USER);
      localStorage.setItem('lumen_guest_mode', 'true');
      setCurrentView('journey');
      document.documentElement.style.fontSize = '';
      document.body.classList.remove('high-contrast', 'reduced-motion');
    } catch (error) {}
  }, [user, guestUser]);

  const handleTopicClick = (prompt: string) => {
    setStartPrompt(prompt);
    setActiveChatId(null); // Start fresh
    setCurrentView('chat');
    if (window.innerWidth < 768) setIsSidebarOpen(false);
  };

  const selectChat = (id: string) => {
    setActiveChatId(id);
    setCurrentView('chat');
    if (window.innerWidth < 768) setIsSidebarOpen(false);
  };

  const deleteChat = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!window.confirm("Delete this conversation?")) return;
    try {
      if (effectiveUser.uid === 'guest-dev-user') {
        const filtered = recentChats.filter(c => c.id !== id);
        setRecentChats(filtered);
        localStorage.setItem('lumen_chats', JSON.stringify(filtered));
      } else if (db) {
        await deleteDoc(doc(db, 'users', effectiveUser.uid, 'chats', id));
      }
      if (activeChatId === id) setActiveChatId(null);
    } catch (err) {}
  };

  if (isAuthLoading) {
    return (
      <div className="h-screen flex items-center justify-center bg-brand-50" role="status" aria-label="Loading Bible Chat">
        <div className="animate-pulse flex flex-col items-center">
          <div className="w-12 h-12 bg-brand-200 rounded-full mb-4"></div>
          <div className="h-4 w-32 bg-brand-200 rounded"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-brand-50 text-slate-800 overflow-hidden font-sans relative">
      {effectiveUser && <ReminderListener userId={effectiveUser.uid} />}
      {showAuthModal && <LoginScreen onLoginSuccess={() => setShowAuthModal(false)} onGuestLogin={() => setShowAuthModal(false)} onClose={() => setShowAuthModal(false)} isDemoMode={isDemoMode} />}
      {isSidebarOpen && <div className="fixed inset-0 bg-black/20 backdrop-blur-sm z-40 md:hidden" aria-hidden="true" onClick={() => setIsSidebarOpen(false)}></div>}

      <aside 
        className={`fixed md:static inset-y-0 left-0 z-50 w-72 bg-white border-r border-brand-100 transform transition-transform duration-300 ease-in-out flex flex-col ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}
        aria-label="Sidebar navigation"
      >
        <div className="p-6 flex items-center justify-center border-b border-brand-50/50">
          <div className="w-10 h-10 bg-brand-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-brand-500/30 mr-3">
            <DoveIcon className="w-6 h-6" />
          </div>
          <div>
            <h1 className="font-display text-xl font-semibold text-slate-800 leading-none">Bible Chat</h1>
            <span className="text-[10px] font-medium text-brand-400 uppercase tracking-widest">Holy Bible Study</span>
          </div>
        </div>

        <nav className="flex-1 overflow-y-auto p-4 space-y-6" aria-label="Main navigation menu">
          <div className="space-y-1">
            <p className="px-4 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2" id="main-nav-label">Main</p>
            <ul className="space-y-1" aria-labelledby="main-nav-label">
              <li>
                <button 
                  onClick={() => { setCurrentView('journey'); setIsSidebarOpen(false); }} 
                  aria-current={currentView === 'journey' ? 'page' : undefined}
                  className={`w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl transition-colors ${currentView === 'journey' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}
                >
                  <MapIcon className="w-5 h-5" />
                  <span className="font-medium">Journey</span>
                </button>
              </li>
              <li>
                <button 
                  onClick={() => { setCurrentView('chat'); setActiveChatId(null); setIsSidebarOpen(false); }} 
                  aria-current={currentView === 'chat' && !activeChatId ? 'page' : undefined}
                  className={`w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl transition-colors ${currentView === 'chat' && !activeChatId ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}
                >
                  <PlusIcon className="w-5 h-5" />
                  <span className="font-medium">New Study</span>
                </button>
              </li>
              <li>
                <button 
                  onClick={() => { setCurrentView('illustrator'); setIsSidebarOpen(false); }} 
                  aria-current={currentView === 'illustrator' ? 'page' : undefined}
                  className={`w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl transition-colors ${currentView === 'illustrator' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}
                >
                  <ImageIcon className="w-5 h-5" />
                  <span className="font-medium">Illustrator</span>
                </button>
              </li>
              <li>
                <button 
                  onClick={() => { setCurrentView('prayer'); setIsSidebarOpen(false); }} 
                  aria-current={currentView === 'prayer' ? 'page' : undefined}
                  className={`w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl transition-colors ${currentView === 'prayer' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}
                >
                  <HandsIcon className="w-5 h-5" />
                  <span className="font-medium">Prayer Wall</span>
                </button>
              </li>
              <li>
                <button 
                  onClick={() => { setCurrentView('favorites'); setIsSidebarOpen(false); }} 
                  aria-current={currentView === 'favorites' ? 'page' : undefined}
                  className={`w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl transition-colors ${currentView === 'favorites' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}
                >
                  <BookmarkIcon className="w-5 h-5" />
                  <span className="font-medium">Favorites</span>
                </button>
              </li>
            </ul>
          </div>

          {recentChats.length > 0 && (
            <div className="space-y-1">
              <p className="px-4 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2" id="recent-chats-label">Recent Chats</p>
              <ul className="max-h-64 overflow-y-auto space-y-1 scrollbar-hide" aria-labelledby="recent-chats-label">
                {recentChats.map(chat => (
                  <li key={chat.id}>
                    <button 
                      onClick={() => selectChat(chat.id)} 
                      aria-current={activeChatId === chat.id ? 'true' : undefined}
                      className={`w-full group flex items-center justify-between px-4 py-2.5 rounded-xl transition-all ${activeChatId === chat.id ? 'bg-brand-100 text-brand-800' : 'text-slate-600 hover:bg-slate-50'}`}
                    >
                      <div className="flex items-center space-x-3 overflow-hidden">
                        <MessageCircleIcon className="w-4 h-4 shrink-0 text-brand-300" />
                        <div className="flex flex-col text-left overflow-hidden">
                          <span className="text-sm font-medium truncate">{chat.title || 'Conversation'}</span>
                          <span className="text-[10px] text-slate-400 flex items-center"><ClockIcon className="w-2.5 h-2.5 mr-1" />{new Date(chat.timestamp).toLocaleDateString()}</span>
                        </div>
                      </div>
                      <button 
                        onClick={(e) => deleteChat(e, chat.id)} 
                        aria-label={`Delete conversation ${chat.title || 'Conversation'}`}
                        className="opacity-0 group-hover:opacity-100 p-1 text-slate-400 hover:text-red-500 rounded-md transition-opacity"
                      >
                        <TrashIcon className="w-3.5 h-3.5" />
                      </button>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          )}

          <div className="space-y-1">
            <p className="px-4 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2" id="topics-nav-label">Suggested Topics</p>
            <ul className="space-y-1" aria-labelledby="topics-nav-label">
              {TOPICS.slice(0, 4).map((topic) => (
                <li key={topic.id}>
                  <button onClick={() => handleTopicClick(topic.prompt)} className="w-full flex items-center space-x-3 px-4 py-2.5 rounded-xl text-slate-600 hover:bg-brand-50 hover:text-brand-700 transition-all group">
                    <div className="text-slate-400 group-hover:text-brand-500 transition-colors">{topic.icon}</div>
                    <span className="font-medium text-sm">{topic.label}</span>
                  </button>
                </li>
              ))}
            </ul>
          </div>
        </nav>

        <div className="p-4 border-t border-slate-100 space-y-1">
           <button 
             onClick={() => { setCurrentView('accessibility'); setIsSidebarOpen(false); }} 
             aria-current={currentView === 'accessibility' ? 'page' : undefined}
             className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-colors ${currentView === 'accessibility' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}
           >
             <AccessibilityIcon className="w-5 h-5" />
             <span className="font-medium">Accessibility</span>
           </button>
           <button 
             onClick={() => { setCurrentView('settings'); setIsSidebarOpen(false); }} 
             aria-current={currentView === 'settings' ? 'page' : undefined}
             className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-colors ${currentView === 'settings' ? 'bg-brand-50 text-brand-700' : 'text-slate-600 hover:bg-slate-50'}`}
           >
             <SettingsIcon className="w-5 h-5" />
             <span className="font-medium">Settings</span>
           </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full relative w-full" role="region" aria-label="Main content">
        <header className="md:hidden flex items-center justify-between p-4 bg-white border-b border-brand-100">
          <button 
            onClick={() => setIsSidebarOpen(true)} 
            className="p-2 text-slate-600 rounded-lg hover:bg-slate-50"
            aria-label="Open sidebar menu"
          >
            <MenuIcon className="w-6 h-6" />
          </button>
          <span className="font-display font-semibold text-lg text-slate-800">Bible Chat</span>
          <div className="w-10"></div>
        </header>

        <div className="flex-1 overflow-hidden relative bg-slate-50">
          <div className="relative z-10 h-full flex flex-col max-w-5xl mx-auto w-full">
             <div className="flex-1 h-full overflow-hidden">
               {currentView === 'journey' && <Journey userId={effectiveUser.uid} onNavigateToChat={handleTopicClick} />}
               {currentView === 'chat' && <Chat userId={effectiveUser.uid} chatId={activeChatId} onChatCreated={setActiveChatId} initialPrompt={startPrompt} onClearInitialPrompt={() => setStartPrompt(undefined)} />}
               {currentView === 'illustrator' && <BibleIllustrator />}
               {currentView === 'prayer' && <PrayerWall userId={effectiveUser.uid} onPrayWithAI={handleTopicClick} />}
               {currentView === 'favorites' && <Favorites userId={effectiveUser.uid} />}
               {currentView === 'zodiac' && <ZodiacDaily userId={effectiveUser.uid} />}
               {currentView === 'about' && <About />}
               {currentView === 'accessibility' && <AccessibilitySettings userId={effectiveUser.uid} />}
               {currentView === 'settings' && <ProfileSettings userId={effectiveUser.uid} userEmail={effectiveUser.email} onLogout={handleLogout} />}
             </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { PrayerRequest } from '../types';
import { PlusIcon, CheckIcon, TrashIcon, XIcon, HeartIcon, SearchIcon, SparklesIcon, ArrowUpIcon, ArrowDownIcon, ShareIcon, MicrophoneIcon, MessageCircleIcon, BellIcon, ClockIcon, WandIcon } from './Icons';
import { db } from '../services/firebase';
import { collection, addDoc, updateDoc, deleteDoc, doc, onSnapshot, query, orderBy } from 'firebase/firestore';
import { enhancePrayerRequest } from '../services/geminiService';

interface PrayerWallProps {
  userId: string;
  onPrayWithAI: (prompt: string) => void;
}

export const PrayerWall: React.FC<PrayerWallProps> = ({ 
  userId,
  onPrayWithAI
}) => {
  const [prayers, setPrayers] = useState<PrayerRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);

  // Form State
  const [newTitle, setNewTitle] = useState('');
  const [newContent, setNewContent] = useState('');
  const [newDescription, setNewDescription] = useState('');
  const [enableReminder, setEnableReminder] = useState(false);
  const [reminderDate, setReminderDate] = useState('');
  const [isEnhancing, setIsEnhancing] = useState(false);

  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');
  const [recordingField, setRecordingField] = useState<'title' | 'content' | 'description' | null>(null);
  const recognitionRef = useRef<any>(null);

  // Load Data
  useEffect(() => {
    if (!userId) return;

    // Guest Fallback
    if (userId === 'guest-dev-user') {
        const local = localStorage.getItem('lumen_prayers');
        if (local) setPrayers(JSON.parse(local));
        setLoading(false);
        return;
    }

    if (!db) {
        setLoading(false);
        return;
    }

    // Firebase Realtime
    const q = query(collection(db, 'users', userId, 'prayers'), orderBy('date', 'desc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const loadedPrayers = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as PrayerRequest[];
      setPrayers(loadedPrayers);
      setLoading(false);
    });
    return () => unsubscribe();
  }, [userId]);

  // Helper to update local storage for guest
  const updateLocalPrayers = (newPrayers: PrayerRequest[]) => {
    setPrayers(newPrayers);
    localStorage.setItem('lumen_prayers', JSON.stringify(newPrayers));
  };

  const submitPrayer = async (withAI: boolean) => {
    if (!newTitle.trim() || !newContent.trim()) return;

    let reminderTime = undefined;
    if (enableReminder && reminderDate) {
        reminderTime = new Date(reminderDate).getTime();
    }

    const newPrayerData = {
      title: newTitle,
      content: newContent,
      description: newDescription,
      date: Date.now(),
      isAnswered: false,
      reminderTime: reminderTime
    };

    try {
      if (userId === 'guest-dev-user') {
          const newPrayer = { ...newPrayerData, id: Date.now().toString() };
          updateLocalPrayers([newPrayer, ...prayers]);
      } else if (db) {
          await addDoc(collection(db, 'users', userId, 'prayers'), newPrayerData);
      }

      if (withAI) {
        const prompt = `I have a prayer request. Title: "${newTitle}". Details: "${newContent}". ${newDescription ? `Additional Context: "${newDescription}".` : ''} Please lead me in a personalized prayer for this specific situation, mentioning the names and details I provided.`;
        onPrayWithAI(prompt);
      }

      setNewTitle('');
      setNewContent('');
      setNewDescription('');
      setEnableReminder(false);
      setReminderDate('');
      setShowForm(false);
    } catch (e) {
      console.error("Error adding prayer", e);
    }
  };

  const handleToggleAnswered = async (id: string, currentStatus: boolean) => {
    if (userId === 'guest-dev-user') {
        const updated = prayers.map(p => p.id === id ? { ...p, isAnswered: !currentStatus } : p);
        updateLocalPrayers(updated);
    } else if (db) {
        const prayerRef = doc(db, 'users', userId, 'prayers', id);
        await updateDoc(prayerRef, { isAnswered: !currentStatus });
    }
  };

  const handleDeletePrayer = async (id: string) => {
    if (window.confirm("Delete this prayer request?")) {
      if (userId === 'guest-dev-user') {
          const updated = prayers.filter(p => p.id !== id);
          updateLocalPrayers(updated);
      } else if (db) {
          await deleteDoc(doc(db, 'users', userId, 'prayers', id));
      }
    }
  };

  const handleRefine = async () => {
    if (!newContent.trim()) return;
    setIsEnhancing(true);
    try {
      const refined = await enhancePrayerRequest(newContent);
      setNewContent(refined);
    } catch (e) {
      console.error("Error enhancing prayer", e);
    } finally {
      setIsEnhancing(false);
    }
  };

  const toggleRecording = (field: 'title' | 'content' | 'description') => {
    if (recordingField === field) {
      if (recognitionRef.current) recognitionRef.current.stop();
      setRecordingField(null);
      return;
    }
    if (!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)) {
      alert("Voice input is not supported in this browser.");
      return;
    }
    // @ts-ignore
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    const recognition = new SpeechRecognition();
    recognitionRef.current = recognition;
    recognition.lang = 'en-US';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => setRecordingField(field);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      if (field === 'title') setNewTitle(prev => (prev ? prev + ' ' : '') + transcript);
      else if (field === 'content') setNewContent(prev => (prev ? prev + ' ' : '') + transcript);
      else if (field === 'description') setNewDescription(prev => (prev ? prev + ' ' : '') + transcript);
    };
    recognition.onend = () => setRecordingField(null);
    recognition.start();
  };

  const filteredPrayers = prayers
    .filter(prayer => 
      prayer.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      prayer.content.toLowerCase().includes(searchQuery.toLowerCase())
    )
    .sort((a, b) => sortOrder === 'desc' ? b.date - a.date : a.date - b.date);

  return (
    <div className="flex flex-col h-full relative bg-slate-50" role="region" aria-label="Prayer Wall">
       {/* Header */}
       <div className="shrink-0 px-6 py-4 bg-white/80 backdrop-blur-md border-b border-brand-100 flex justify-between items-center z-10">
        <div className="flex items-center space-x-3">
           <span className="text-brand-800 font-display font-semibold tracking-wide text-lg">Prayer Wall</span>
        </div>
        <button 
          onClick={() => setShowForm(true)}
          className="flex items-center gap-2 px-4 py-2 bg-brand-600 text-white rounded-full shadow-md hover:bg-brand-700 transition-all text-sm font-medium"
          aria-label="Add a new prayer request"
        >
          <PlusIcon className="w-4 h-4" />
          <span>Add Prayer</span>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 sm:p-6">
        {loading ? (
            <div className="flex justify-center py-10" role="status" aria-label="Loading prayers"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-brand-600"></div></div>
        ) : (
          <>
            <div className="max-w-4xl mx-auto mb-6 flex gap-3">
              <div className="relative flex-1">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <SearchIcon className="h-5 w-5 text-slate-400" />
                </div>
                <label htmlFor="prayerSearch" className="sr-only">Search prayers</label>
                <input
                  id="prayerSearch"
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="block w-full pl-10 pr-3 py-3 border border-brand-100 rounded-xl bg-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-brand-200"
                  placeholder="Search prayers..."
                />
              </div>
              <button
                onClick={() => setSortOrder(prev => prev === 'desc' ? 'asc' : 'desc')}
                className="flex items-center gap-2 px-4 py-2 bg-white border border-brand-100 rounded-xl text-slate-600 font-medium hover:bg-brand-50"
                aria-label={`Sort prayers by date ${sortOrder === 'desc' ? 'ascending' : 'descending'}`}
              >
                {sortOrder === 'desc' ? <ArrowDownIcon className="w-4 h-4" /> : <ArrowUpIcon className="w-4 h-4" />}
              </button>
            </div>

            <div className="max-w-4xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-4">
                {filteredPrayers.map(prayer => (
                  <div 
                    key={prayer.id}
                    className={`group relative flex flex-col p-5 rounded-2xl border transition-all duration-200 ${
                        prayer.isAnswered 
                        ? 'bg-slate-50 border-slate-200 opacity-75' 
                        : 'bg-white border-brand-100 shadow-sm hover:shadow-md'
                    }`}
                    role="article"
                    aria-label={`Prayer: ${prayer.title}`}
                  >
                      <div className="flex justify-between items-start mb-2">
                        <h3 className={`font-serif font-semibold text-lg ${prayer.isAnswered ? 'text-slate-400 line-through' : 'text-brand-900'}`}>
                            {prayer.title}
                        </h3>
                        <div className="flex space-x-1">
                            <button 
                              onClick={() => handleToggleAnswered(prayer.id, prayer.isAnswered)}
                              className={`p-1.5 rounded-full transition-colors ${prayer.isAnswered ? 'bg-green-100 text-green-600' : 'hover:bg-slate-100 text-slate-400'}`}
                              aria-label={prayer.isAnswered ? "Mark as unanswered" : "Mark as answered"}
                            >
                              <CheckIcon className="w-4 h-4" />
                            </button>
                            <button 
                              onClick={() => handleDeletePrayer(prayer.id)}
                              className="p-1.5 rounded-full hover:bg-red-50 text-slate-300 hover:text-red-400 transition-colors"
                              aria-label={`Delete prayer ${prayer.title}`}
                            >
                              <TrashIcon className="w-4 h-4" />
                            </button>
                        </div>
                      </div>
                      <p className="text-sm leading-relaxed mb-3 text-slate-600">{prayer.content}</p>

                      {prayer.reminderTime && prayer.reminderTime > Date.now() && (
                          <div className="mb-3 flex items-center text-xs font-semibold text-blue-500 bg-blue-50 w-fit px-2 py-1 rounded-md" aria-label={`Scheduled reminder for ${new Date(prayer.reminderTime).toLocaleString()}`}>
                              <BellIcon className="w-3 h-3 mr-1" />
                              <span>Reminder: {new Date(prayer.reminderTime).toLocaleString()}</span>
                          </div>
                      )}

                      {prayer.description && (
                        <div className="mb-4 p-3 rounded-lg text-sm bg-brand-50/50 text-slate-600">
                          {prayer.description}
                        </div>
                      )}
                      <div className="mt-auto pt-4 border-t border-slate-50 flex flex-wrap gap-y-2 justify-between items-center">
                        <span className="text-xs text-brand-300 flex items-center"><HeartIcon className="w-3 h-3 mr-1"/>{new Date(prayer.date).toLocaleDateString()}</span>
                        {!prayer.isAnswered && (
                          <button 
                            onClick={() => onPrayWithAI(`I have a prayer request regarding "${prayer.title}". Details: "${prayer.content}". Please lead me in a personalized prayer specifically for this situation, referencing these details.`)}
                            className="flex items-center space-x-1.5 px-4 py-2 rounded-full bg-brand-50 text-brand-700 text-xs font-bold uppercase tracking-wider hover:bg-brand-100 transition-colors border border-brand-200 shadow-sm"
                            aria-label={`Open AI prayer for ${prayer.title}`}
                          >
                            <SparklesIcon className="w-4 h-4 text-gold-500" />
                            <span>Pray with AI</span>
                          </button>
                        )}
                      </div>
                  </div>
                ))}
            </div>
          </>
        )}
      </div>

      {/* Add Prayer Modal */}
      {showForm && (
         <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/20 backdrop-blur-sm p-4" role="dialog" aria-modal="true" aria-labelledby="modal-title">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200 max-h-[90vh] overflow-y-auto">
               <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-brand-50/50">
                  <h3 id="modal-title" className="font-display font-semibold text-brand-800">New Prayer Request</h3>
                  <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-slate-600" aria-label="Close modal"><XIcon className="w-5 h-5" /></button>
               </div>
               <form className="p-6 space-y-4" onSubmit={(e) => e.preventDefault()}>
                  <div>
                     <label htmlFor="prayerTitle" className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Title</label>
                     <div className="relative">
                       <input 
                          id="prayerTitle"
                          type="text" 
                          value={newTitle}
                          onChange={(e) => setNewTitle(e.target.value)}
                          className="w-full px-4 py-2 pr-10 rounded-xl border border-slate-200 focus:border-brand-400 focus:ring-2 focus:ring-brand-100 outline-none"
                          required
                       />
                       <button type="button" onClick={() => toggleRecording('title')} className={`absolute right-2 top-1/2 -translate-y-1/2 p-1.5 rounded-full ${recordingField === 'title' ? 'text-red-500' : 'text-slate-400'}`} aria-label="Voice input for title"><MicrophoneIcon className="w-4 h-4" /></button>
                     </div>
                  </div>
                  <div>
                     <div className="flex justify-between items-center mb-1">
                        <label htmlFor="prayerContent" className="block text-xs font-bold text-slate-500 uppercase tracking-wider">Request</label>
                        {newContent.length > 10 && (
                          <button 
                            type="button" 
                            onClick={handleRefine}
                            disabled={isEnhancing}
                            className="text-[10px] font-bold text-brand-600 uppercase tracking-wider flex items-center space-x-1 hover:text-brand-800 transition-colors disabled:opacity-50"
                            aria-label="Refine prayer request using AI"
                          >
                             {isEnhancing ? (
                               <span className="animate-pulse">Refining...</span>
                             ) : (
                               <>
                                 <WandIcon className="w-3 h-3" />
                                 <span>Refine with AI</span>
                               </>
                             )}
                          </button>
                        )}
                     </div>
                     <div className="relative">
                       <textarea 
                          id="prayerContent"
                          value={newContent}
                          onChange={(e) => setNewContent(e.target.value)}
                          rows={3}
                          className="w-full px-4 py-2 pr-10 rounded-xl border border-slate-200 focus:border-brand-400 focus:ring-2 focus:ring-brand-100 outline-none resize-none"
                          required
                       />
                       <button type="button" onClick={() => toggleRecording('content')} className={`absolute right-2 top-2 p-1.5 rounded-full ${recordingField === 'content' ? 'text-red-500' : 'text-slate-400'}`} aria-label="Voice input for request content"><MicrophoneIcon className="w-4 h-4" /></button>
                     </div>
                  </div>

                  {/* Reminder Section */}
                  <div className="bg-slate-50 rounded-xl p-4 border border-slate-100" role="group" aria-labelledby="reminder-label">
                     <div className="flex items-center justify-between mb-2">
                        <div id="reminder-label" className="flex items-center space-x-2 text-slate-700 font-semibold text-sm">
                            <ClockIcon className="w-4 h-4 text-brand-500" />
                            <span>Set Reminder</span>
                        </div>
                        <label className="relative inline-flex items-center cursor-pointer">
                            <input type="checkbox" className="sr-only peer" checked={enableReminder} onChange={(e) => setEnableReminder(e.target.checked)} aria-label="Enable reminder for this prayer" />
                            <div className="w-9 h-5 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:bg-brand-600"></div>
                        </label>
                     </div>

                     {enableReminder && (
                        <div className="mt-2 animate-in fade-in slide-in-from-top-2">
                            <label htmlFor="reminderDate" className="sr-only">Choose reminder date and time</label>
                            <input 
                                id="reminderDate"
                                type="datetime-local" 
                                value={reminderDate}
                                onChange={(e) => setReminderDate(e.target.value)}
                                className="w-full px-4 py-2 rounded-lg border border-slate-200 text-sm focus:ring-2 focus:ring-brand-100 outline-none text-slate-600"
                            />
                            <p className="text-[10px] text-slate-400 mt-1 ml-1">We'll notify you if the app is open.</p>
                        </div>
                     )}
                  </div>

                  <div className="grid grid-cols-2 gap-3 pt-2">
                    <button 
                      type="button"
                      onClick={() => submitPrayer(false)} 
                      className="px-4 py-3 rounded-xl bg-slate-100 text-slate-600 font-semibold hover:bg-slate-200 transition-colors"
                      aria-label="Save this prayer request to the wall"
                    >
                      Save to Wall
                    </button>
                    <button 
                      type="button"
                      onClick={() => submitPrayer(true)} 
                      className="px-4 py-3 rounded-xl bg-brand-600 text-white font-semibold hover:bg-brand-700 shadow-lg flex items-center justify-center gap-2"
                      aria-label="Save this prayer and open AI prayer companion"
                    >
                      <SparklesIcon className="w-4 h-4 text-gold-400" />
                      <span>Save & Pray</span>
                    </button>
                  </div>
               </form>
            </div>
         </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { ActivityLog } from '../types';
import { 
  CalendarIcon, FireIcon, FeatherIcon, BookIcon, LeafIcon, ChevronDownIcon, CheckIcon, TrashIcon, EditIcon, SparklesIcon
} from './Icons';
import { db } from '../services/firebase';
import { collection, addDoc, updateDoc, deleteDoc, doc, onSnapshot, query, orderBy } from 'firebase/firestore';
import { generateJournalInsight } from '../services/geminiService';

interface Task {
  id: string;
  title: string;
  duration: string;
  icon: React.ReactNode;
  color: string;
  description: string;
  placeholder: string;
  actionLabel?: string;
  actionPrompt?: string;
}

const TASKS: Task[] = [
  { 
    id: 'journal', 
    title: 'Spiritual Journal', 
    duration: '1 MIN', 
    icon: <FeatherIcon className="w-5 h-5" />, 
    color: 'bg-green-100 text-green-600',
    description: "Reflect on today's blessings. Write down three things you are grateful for and how you've seen God's hand in your life today.",
    placeholder: "Today I am grateful for..."
  },
  { 
    id: 'verse', 
    title: 'Your Verse', 
    duration: '3 MIN', 
    icon: <BookIcon className="w-5 h-5" />, 
    color: 'bg-blue-100 text-blue-600',
    description: "Read Psalm 23 today. Focus on the comfort of the Shepherd's presence in the valley. Meditate on His guidance.",
    placeholder: "This verse speaks to me because...",
    actionLabel: "Read Psalm 23",
    actionPrompt: "Please show me Psalm 23 and guide me through a short meditation on it."
  },
  { 
    id: 'devotional', 
    title: 'Personalized Devotional', 
    duration: '3 MIN', 
    icon: <LeafIcon className="w-5 h-5" />, 
    color: 'bg-purple-100 text-purple-600',
    description: "Today's devotional focuses on Trust. Learn how letting go of control can bring a deeper sense of peace and purpose.",
    placeholder: "My takeaway from today's devotional is...",
    actionLabel: "Start Devotional",
    actionPrompt: "Please share a short devotional about Trust and letting go of control, including a relevant scripture."
  },
];

interface JourneyProps {
  userId: string;
  onNavigateToChat: (prompt: string) => void;
}

export const Journey: React.FC<JourneyProps> = ({ userId, onNavigateToChat }) => {
  const [expandedId, setExpandedId] = useState<string | null>('journal');
  const [logs, setLogs] = useState<ActivityLog[]>([]);
  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);
  const [inputContent, setInputContent] = useState('');
  const [editingLogId, setEditingLogId] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Load Logs
  useEffect(() => {
    if (!userId) return;

    if (userId === 'guest-dev-user') {
        const local = localStorage.getItem('lumen_logs');
        if (local) setLogs(JSON.parse(local));
        return;
    }

    if (!db) return;

    const q = query(collection(db, 'users', userId, 'logs'), orderBy('timestamp', 'desc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const loadedLogs = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as ActivityLog[];
      setLogs(loadedLogs);
    });
    return () => unsubscribe();
  }, [userId]);

  const updateLocalLogs = (newLogs: ActivityLog[]) => {
    setLogs(newLogs);
    localStorage.setItem('lumen_logs', JSON.stringify(newLogs));
  };

  const toggleExpand = (id: string) => {
    if (activeTaskId && activeTaskId !== id) {
        setActiveTaskId(null);
        setInputContent('');
        setEditingLogId(null);
    }
    setExpandedId(expandedId === id ? null : id);
  };

  const handleStartTask = (task: Task) => {
    setActiveTaskId(task.id);
    setExpandedId(task.id);
    setInputContent('');
    setEditingLogId(null);
  };

  const handleSaveLog = async () => {
    if (!activeTaskId && !editingLogId) return;
    if (!inputContent.trim()) return;

    try {
        if (editingLogId) {
            if (userId === 'guest-dev-user') {
                const updated = logs.map(l => l.id === editingLogId ? { ...l, content: inputContent } : l);
                updateLocalLogs(updated);
            } else if (db) {
                const logRef = doc(db, 'users', userId, 'logs', editingLogId);
                await updateDoc(logRef, { content: inputContent });
            }
            setEditingLogId(null);
        } else if (activeTaskId) {
            const task = TASKS.find(t => t.id === activeTaskId);
            if (!task) return;
            const newLogData = {
                taskId: task.id,
                taskTitle: task.title,
                content: inputContent,
                timestamp: Date.now(),
            };

            if (userId === 'guest-dev-user') {
                const newLog = { ...newLogData, id: Date.now().toString() };
                updateLocalLogs([newLog, ...logs]);
            } else if (db) {
                await addDoc(collection(db, 'users', userId, 'logs'), newLogData);
            }
        }
        setActiveTaskId(null);
        setInputContent('');
    } catch (e) {
        console.error("Error saving log", e);
    }
  };

  const handleEditLog = (log: ActivityLog) => {
    setEditingLogId(log.id);
    setActiveTaskId(log.taskId);
    setInputContent(log.content);
    setExpandedId(log.taskId);
  };

  const handleDeleteLog = async (id: string) => {
    if (window.confirm('Are you sure you want to delete this entry?')) {
        if (userId === 'guest-dev-user') {
            const updated = logs.filter(l => l.id !== id);
            updateLocalLogs(updated);
        } else if (db) {
            await deleteDoc(doc(db, 'users', userId, 'logs', id));
        }
    }
  };

  const handleDeepenReflection = async () => {
    if (!inputContent.trim() || isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const insight = await generateJournalInsight(inputContent);
      if (insight) {
        setInputContent(prev => `${prev}\n\n--- Spiritual Insight ---\n${insight}`);
      }
    } catch (e) {
      console.error("Analysis failed", e);
    } finally {
      setIsAnalyzing(false);
    }
  };

  // Progress Calculation
  const today = new Date().setHours(0,0,0,0);
  const todaysLogs = logs.filter(log => log.timestamp >= today);
  const uniqueTasksDone = new Set(todaysLogs.map(l => l.taskId)).size;
  const progress = Math.min(100, Math.round((uniqueTasksDone / TASKS.length) * 100));
  const currentDateDisplay = new Date().getDate();

  return (
    <div className="h-full overflow-y-auto bg-slate-50 relative" role="main" aria-label="Daily Spiritual Journey">
        {/* Background Decoration */}
       <div className="absolute inset-0 overflow-hidden pointer-events-none" aria-hidden="true">
          <div className="absolute top-0 left-0 w-full h-96 bg-gradient-to-b from-orange-50/50 to-transparent"></div>
       </div>

      <div className="relative z-10 max-w-md mx-auto p-6 space-y-8 pb-32">

        <div className="text-center pt-4 space-y-2">
          <h1 className="font-display text-4xl font-bold text-slate-800 leading-tight">Grow Spiritually</h1>
        </div>

        <div className="bg-white rounded-[2rem] shadow-xl shadow-orange-100/50 overflow-hidden border border-orange-50/50" role="region" aria-label="Today's progress summary">
          <div className="p-6 pb-8 bg-gradient-to-b from-white to-orange-50/30">
            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center space-x-4">
                <div className="w-12 h-12 rounded-full bg-gradient-to-br from-gold-400 to-gold-500 flex items-center justify-center text-white font-display font-bold text-xl shadow-lg shadow-gold-200" aria-hidden="true">S</div>
                <div>
                  <h2 className="text-xl font-bold text-slate-800">Today's Journey</h2>
                  <div className="text-xs text-gold-600 font-medium mt-0.5">God's Love and Grace</div>
                </div>
              </div>
              <div className="flex items-center bg-slate-800 text-white px-3 py-1.5 rounded-lg space-x-2 shadow-lg" aria-label={`Current day: ${currentDateDisplay}`}>
                <CalendarIcon className="w-4 h-4 text-slate-400" />
                <span className="text-gold-400 font-bold">{currentDateDisplay}</span>
              </div>
            </div>

            <div className="space-y-2">
               <div className="flex justify-between items-end px-1">
                  <span className="text-lg font-medium text-slate-800">Progress today</span>
                  <span className="text-lg font-bold text-gold-500" aria-label={`${progress} percent complete`}>{progress}%</span>
               </div>
               <div className="h-2 w-full bg-orange-100 rounded-full overflow-hidden" role="progressbar" aria-valuenow={progress} aria-valuemin={0} aria-valuemax={100}>
                  <div className="h-full bg-gold-500 rounded-full transition-all duration-1000 ease-out" style={{ width: `${progress}%` }}></div>
               </div>
            </div>
          </div>
        </div>

        <div className="space-y-3" role="list" aria-label="Daily tasks">
          {TASKS.map((task) => {
            const isCompletedToday = todaysLogs.some(l => l.taskId === task.id);
            const isWriting = activeTaskId === task.id;
            const isExpanded = expandedId === task.id;

            return (
                <div 
                  key={task.id} 
                  role="listitem"
                  className={`bg-white/80 backdrop-blur-sm rounded-2xl shadow-sm border overflow-hidden transition-all duration-300 hover:shadow-md ${isCompletedToday ? 'border-green-100' : 'border-white'}`}
                >
                <button 
                  id={`task-btn-${task.id}`}
                  aria-expanded={isExpanded}
                  aria-controls={`task-content-${task.id}`}
                  className={`w-full p-4 flex items-center justify-between cursor-pointer bg-gradient-to-r ${isCompletedToday ? 'from-green-50/50 to-white' : 'from-slate-100 to-slate-50'}`} 
                  onClick={() => toggleExpand(task.id)}
                >
                    <div className="flex items-center space-x-3">
                        <div className={`p-2 rounded-lg ${task.color} bg-opacity-20 relative`} aria-hidden="true">
                            {task.icon}
                            {isCompletedToday && <div className="absolute -top-1 -right-1 w-4 h-4 bg-green-500 rounded-full border-2 border-white flex items-center justify-center"><CheckIcon className="w-2.5 h-2.5 text-white" /></div>}
                        </div>
                        <div className="flex flex-col text-left">
                            <span className="font-bold text-slate-700 text-sm tracking-wide uppercase">{task.title} {isCompletedToday ? '(Completed)' : ''}</span>
                            <span className="text-[10px] font-semibold text-slate-400 tracking-wider">{task.duration} ESTIMATED</span>
                        </div>
                    </div>
                    <ChevronDownIcon className={`w-5 h-5 text-slate-400 transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`} />
                </button>

                {isExpanded && (
                    <div id={`task-content-${task.id}`} className="p-5 text-sm text-slate-600 bg-white border-t border-slate-50" role="region" aria-labelledby={`task-btn-${task.id}`}>
                        <p className="mb-4 leading-relaxed text-slate-500">{task.description}</p>

                        {!isWriting && task.actionLabel && task.actionPrompt && (
                          <button onClick={(e) => { e.stopPropagation(); onNavigateToChat(task.actionPrompt!); }} className="w-full mb-4 py-2.5 rounded-xl border border-brand-200 text-brand-600 font-semibold text-xs uppercase tracking-wider hover:bg-brand-50 transition-colors flex items-center justify-center space-x-2" aria-label={`Start activity: ${task.actionLabel}`}>
                            <SparklesIcon className="w-4 h-4 text-gold-400" />
                            <span>{task.actionLabel}</span>
                          </button>
                        )}

                        {isWriting ? (
                            <div className="space-y-3 animate-in fade-in duration-300">
                                <label htmlFor={`textarea-${task.id}`} className="sr-only">{task.placeholder}</label>
                                <textarea 
                                  id={`textarea-${task.id}`}
                                  value={inputContent} 
                                  onChange={(e) => setInputContent(e.target.value)} 
                                  placeholder={task.placeholder} 
                                  rows={6} 
                                  className="w-full p-3 rounded-xl border border-brand-200 focus:border-brand-400 focus:ring-2 focus:ring-brand-100 outline-none bg-brand-50/30 resize-none" 
                                  autoFocus 
                                />

                                <div className="flex justify-between items-center mb-1">
                                    <button 
                                      onClick={handleDeepenReflection}
                                      disabled={!inputContent.trim() || isAnalyzing}
                                      className="text-xs font-bold text-indigo-600 uppercase tracking-wider flex items-center space-x-1 hover:text-indigo-800 transition-colors disabled:opacity-50"
                                      aria-label="Use AI to deepen your reflection"
                                    >
                                       {isAnalyzing ? (
                                         <span className="animate-pulse">Analyzing...</span>
                                       ) : (
                                         <>
                                           <SparklesIcon className="w-3 h-3" />
                                           <span>Deepen Reflection (AI)</span>
                                         </>
                                       )}
                                    </button>
                                </div>

                                <div className="flex space-x-2">
                                    <button onClick={() => { setActiveTaskId(null); setEditingLogId(null); setInputContent(''); }} className="flex-1 py-2.5 border border-slate-200 text-slate-500 rounded-xl font-medium text-xs uppercase tracking-wider hover:bg-slate-50" aria-label="Cancel reflection entry">Cancel</button>
                                    <button onClick={handleSaveLog} disabled={!inputContent.trim()} className="flex-1 py-2.5 bg-brand-600 text-white rounded-xl font-medium text-xs uppercase tracking-wider hover:bg-brand-700 disabled:opacity-50" aria-label="Save reflection entry">Save Entry</button>
                                </div>
                            </div>
                        ) : (
                            <button onClick={(e) => { e.stopPropagation(); handleStartTask(task); }} className={`w-full py-3 rounded-xl font-bold text-xs uppercase tracking-wider transition-all shadow-sm ${isCompletedToday ? 'bg-green-50 text-green-600 border border-green-100 hover:bg-green-100' : 'bg-brand-600 text-white hover:bg-brand-700'}`} aria-label={`${isCompletedToday ? 'Add another reflection to' : 'Start reflection for'} ${task.title}`}>
                                {isCompletedToday ? 'Add Another Entry' : 'Write Reflection'}
                            </button>
                        )}
                    </div>
                )}
                </div>
            );
          })}
        </div>

        {logs.length > 0 && (
            <div className="pt-6 border-t border-slate-200/60" role="region" aria-label="Activity history">
                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 pl-1">Recent Activity</h3>
                <div className="space-y-4" role="list">
                    {logs.map((log) => (
                        <div key={log.id} role="listitem" className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 group relative">
                            <div className="flex justify-between items-start mb-2">
                                <div className="flex items-center space-x-2">
                                    <span className="text-xs font-bold text-brand-500 uppercase tracking-wide px-2 py-0.5 bg-brand-50 rounded-full border border-brand-100">{log.taskTitle}</span>
                                    <span className="text-xs text-slate-400" aria-label={`Recorded on ${new Date(log.timestamp).toLocaleDateString()}`}>{new Date(log.timestamp).toLocaleDateString()}</span>
                                </div>
                                <div className="flex space-x-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => handleEditLog(log)} className="p-1.5 text-slate-400 hover:text-brand-500 hover:bg-brand-50 rounded-lg" aria-label="Edit entry"><EditIcon className="w-3.5 h-3.5" /></button>
                                    <button onClick={() => handleDeleteLog(log.id)} className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg" aria-label="Delete entry"><TrashIcon className="w-3.5 h-3.5" /></button>
                                </div>
                            </div>
                            <p className="text-sm text-slate-600 leading-relaxed whitespace-pre-wrap font-serif italic" aria-label="Log content">"{log.content}"</p>
                        </div>
                    ))}
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

