      const reader = new FileReader();
      reader.onload = (event) => {
        if (event.target?.result) {
            setSelectedImage(event.target.result as string);
            setError(null);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleEditResult = () => {
    if (imageUrl) {
        setSelectedImage(imageUrl);
        setImageUrl(null);
        setPrompt('');
        setMode('edit');
