  if (!imageUrl) return null;

  return (
    <div className="relative w-full aspect-video rounded-3xl overflow-hidden shadow-2xl shadow-brand-200/50 group border border-brand-100 animate-in fade-in duration-1000">
      <img 
        src={imageUrl} 
