        </nav>

        <div className="p-4 border-t border-slate-100 space-y-1">
           <button 
             onClick={() => { setCurrentView('accessibility'); setIsSidebarOpen(false); }} 
             aria-current={currentView === 'accessibility' ? 'page' : undefined}
